import './style/index.less'
import { useMemo, useRef, useState, useCallback } from 'react'
import { useTranslation } from 'react-i18next'
import {
  Button,
  Form,
  Input,
  Message,
  Select,
  Badge,
  Modal,
  Grid,
  DatePicker,
  Link,
  Radio,
} from '@arco-design/web-react'
import type { TableColumnProps } from '@arco-design/web-react'
import {
  IconEye,
  IconPlus,
  IconSearch,
  IconDelete,
} from '@arco-design/web-react/icon'
import ListFilterHseForm from '@common/components/ListFilterHseForm'
import DeleteConfirmModal from '@common/components/DeleteConfirmModal'
import UnifiedTableStyle from '@common/components/UnifiedTableStyle'
import type { IncidentFilterValues } from '@/types/IncidentReport'
import { useNavigate } from 'react-router-dom'
import {
  saveIncidentReport,
  incidentReportPage,
  incidentDelete,
} from '@/service'
import { useRequest } from 'ahooks'
import { LanguageEnum } from '@common/constants/language'
import { getLanguage } from '@common/utils/localStorage'
import { renderEllipsisText } from '@common/components/EllipsisText'
import { useIsHSEManager } from '@common/hooks/useIsAdmin'
import { EmergencyLocation } from '@/constants/incidentReport'

const FormItem = Form.Item
const Row = Grid.Row
const Col = Grid.Col
const RadioGroup = Radio.Group
const classPrefix = 'incident-report-list'

const FLOOR_OPTIONS = [
  'G',
  'M',
  '1',
  '2',
  '3',
  '4',
  '5',
  '6',
  'RF',
  'P1',
  'P2',
  'P3',
]

const FloorSelector = ({
  value = [],
  onChange,
}: {
  value?: string[]
  onChange?: (val: string[]) => void
}) => {
  const toggle = (floor: string) => {
    const next = value.includes(floor)
      ? value.filter((f) => f !== floor)
      : [...value, floor]
    onChange?.(next)
  }
  return (
    <div className='floor-selector'>
      {FLOOR_OPTIONS.map((floor) => (
        <button
          key={floor}
          type='button'
          className={`floor-btn${value.includes(floor) ? ' selected' : ''}`}
          onClick={() => toggle(floor)}
        >
          {floor}
        </button>
      ))}
    </div>
  )
}

const IncidentReport = () => {
  const { t } = useTranslation(['incidentReport', 'common'])
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const tableRef = useRef<any>(null)
  const [filters, setFilters] = useState<IncidentFilterValues>({})
  const navigate = useNavigate()
  const [reportNewIncidentVisible, setReportNewIncidentVisible] =
    useState(false)
  const [deleteVisible, setDeleteVisible] = useState(false)
  const deleteIdRef = useRef<any>(null)

  const isHSEManager = useIsHSEManager()
  // const isHSEManager = false
  // const isAdmin = false

  const [newIncidentForm] = Form.useForm()
  const [dataInfo, setDataInfo] = useState<any>()
  const [emergencyLocation, setEmergencyLocation] = useState<any>()
  const statusOptions = useMemo(
    () => [
      { label: t('incidentReport:status.open'), value: 0 },
      { label: t('incidentReport:status.underReview'), value: 1 },
      { label: t('incidentReport:status.rejected'), value: 2 },
      { label: t('incidentReport:status.approved'), value: 3 },
    ],
    [t],
  )

  const convertedOptions = useMemo(
    () => [
      { label: t('incidentReport:convertedOptions.yes'), value: 1 },
      { label: t('incidentReport:convertedOptions.no'), value: 0 },
    ],
    [t],
  )

  const statusColor = {
    0: '#4080FF',
    1: '#FF7D00',
    2: '#F5626C',
    3: '#45AD5E',
  }

  const statusText = {
    0: t('incidentReport:status.open'),
    1: t('incidentReport:status.underReview'),
    2: t('incidentReport:status.rejected'),
    3: t('incidentReport:status.approved'),
  }

  //获取表格数据
  const getList = useCallback(
    (page) => {
      const allSearchFields = {
        incidentDetails: filters.incidentDetails?.trim().toLowerCase() || '',
        locationSystem: filters.locationSystem?.trim().toLowerCase() || '',
        status: filters.status,
        covertToAccident: filters.covertToAccident,
        ...page,
      }
      return incidentReportPage(allSearchFields).then((res: any) => {
        res.list = res?.list.map((item) => {
          return {
            ...item,
            name: isLanguageAR ? item?.nameAr : item?.name,
            objectiveName: isLanguageAR
              ? item?.objectiveNameAr
              : item?.objectiveName,
          }
        })
        return res
      })
    },
    [filters],
  )

  const handleSubmit = (values: IncidentFilterValues) => {
    setFilters(values || {})
    tableRef.current?.setPageNum?.(1)
    tableRef.current?.refresh?.()
  }

  const handleReset = () => {
    setFilters({})
    tableRef.current?.setPageNum?.(1)
    tableRef.current?.refresh?.()
  }

  const handleCreate = () => {
    setReportNewIncidentVisible(true)
  }

  const locationType = {
    0: t('incidentReport:form.outOfBuilding'),
    1: t('incidentReport:form.insideBuilding'),
  }

  const columns: TableColumnProps<any>[] = [
    {
      title: t('Incident ID'),
      dataIndex: 'incidentCode',
      width: 220,
      ellipsis: true,
      render: renderEllipsisText,
    },
    {
      title: t('Related Emergency ID'),
      dataIndex: 'relatedEmergencyCode',
      width: 220,
      ellipsis: true,
      render: (_, record) => {
        if (!record?.relatedEmergencyCode || !record?.relatedEmergencyId) {
          return renderEllipsisText(record?.relatedEmergencyCode)
        }
        return (
          <Link
            onClick={() =>
              navigate(
                `/emergency-response/emergency-response-activation/detail/${record.relatedEmergencyId}/active`,
              )
            }
          >
            {renderEllipsisText(record.relatedEmergencyCode)}
          </Link>
        )
      },
    },
    {
      title: t('incidentReport:columns.incidentDetails'),
      dataIndex: 'incidentDetails',
      width: 220,
      ellipsis: true,
      render: (_, record) => {
        const incidentDetails = isLanguageAR
          ? record?.incidentDetailsAr
          : record?.incidentDetails
        return renderEllipsisText(incidentDetails)
      },
    },
    {
      title: t('incidentReport:columns.reportedBy'),
      dataIndex: 'reportedBy',
      width: 180,
      render: (_, record) => {
        const reportedByName = isLanguageAR
          ? record?.reportedByNameAr
          : record?.reportedByName
        return renderEllipsisText(reportedByName)
      },
    },
    // {
    //   title: t('incidentReport:columns.reporterTitle'),
    //   dataIndex: 'reporterTitle',
    //   width: 180,
    //   render: (_, record) => {
    //     const reporterTitle = isLanguageAR
    //       ? record?.reporterTitleAr
    //       : record?.reporterTitle
    //     return renderEllipsisText(reporterTitle)
    //   },
    // },
    {
      title: t('incidentReport:columns.reportDateTime'),
      dataIndex: 'reportDate',
      width: 180,
      render: renderEllipsisText,
    },
    // {
    //   title: t('incidentReport:columns.incidentDateTime'),
    //   dataIndex: 'incidentDate',
    //   width: 180,
    //   render: renderEllipsisText,
    // },
    {
      title: t('Location'),
      dataIndex: 'locationSystem',
      width: 180,
      render: (_, record) => {
        return locationType[record?.locationType]
      },
    },
    {
      title: t('Floor'),
      dataIndex: 'floor',
      width: 120,
      render: (_, record) => {
        return renderEllipsisText(record?.floors?.join(','))
      },
    },
    {
      title: t('common:columns.status'),
      dataIndex: 'status',
      width: 180,
      render: (_, record) => {
        return (
          <div className='incidentReport-columns-status'>
            <Badge
              color={statusColor[record?.status]}
              style={{ marginRight: 4 }}
            />
            {statusText[record?.status]}
          </div>
        )
      },
    },
    {
      title: t('incidentReport:columns.action'),
      dataIndex: 'action',
      width: 100,
      fixed: 'right' as const,
      render: (_value, record) => (
        <>
          <Link
            icon={<IconEye />}
            className='coc-table-link'
            onClick={() =>
              handelIncidentReportDetail(
                record?.incidentReportId,
                record?.status,
              )
            }
          >
            {/* {record?.status == 1 && isHSEManager
              ? t('common:btn.approve')
              : t('common:btn.view')} */}
          </Link>
          <Link
            icon={<IconDelete />}
            className='coc-table-link'
            onClick={() => handleDelete(record?.incidentReportId)}
            disabled={!record?.deletable}
          ></Link>
        </>
      ),
    },
  ]

  const { run: runIncidentDelete, loading: incidentDeleteLoading } = useRequest(
    incidentDelete,
    {
      manual: true,
      onSuccess: () => {
        Message.success('Deleted successfully')
        setDeleteVisible(false)
        deleteIdRef.current = null
        tableRef.current?.refresh?.()
      },
    },
  )

  const handleDelete = (id) => {
    deleteIdRef.current = id
    setDeleteVisible(true)
  }

  const handleDeleteOk = () => {
    const id = deleteIdRef.current
    if (!id) return
    runIncidentDelete({ incidentReportId: id })
  }
  const handelIncidentReportDetail = (id, status) => {
    if (status == 0) {
      navigate(`/incident-report/incident-report-management/addOrEdit/2/${id}`)
    } else if (status == 1) {
      navigate(`/incident-report/incident-report-management/addOrEdit/3/${id}`)
    } else if (status == 2) {
      navigate(`/incident-report/incident-report-management/addOrEdit/4/${id}`)
    } else if (status == 3) {
      navigate(`/incident-report/incident-report-management/addOrEdit/4/${id}`)
    }
  }

  const { run: runSaveIncidentReport, loading: saveIncidentReportLoading } =
    useRequest(saveIncidentReport, {
      manual: true,
      onSuccess: (res: any) => {
        navigate(
          `/incident-report/incident-report-management/addOrEdit/2/${res}`,
          {
            state: {
              data: dataInfo,
            },
          },
        )
        newIncidentForm.resetFields()
        setReportNewIncidentVisible(false)
      },
    })

  const handleOk = () => {
    newIncidentForm.validate().then(() => {
      const data = newIncidentForm.getFieldsValue()
      setDataInfo(data)
      runSaveIncidentReport(data)
    })
  }
  return (
    <div className={`${classPrefix}`}>
      <div className={`${classPrefix}-header`}>
        <div className={`${classPrefix}-title`}>
          {t('incidentReport:title')}
        </div>
        <ListFilterHseForm
          showKeywordInput={false}
          onSubmit={handleSubmit}
          onReset={handleReset}
          renderBtnJsx={
            <Button type='primary' icon={<IconPlus />} onClick={handleCreate}>
              {t('incidentReport:addButton')}
            </Button>
          }
        >
          <div className='search-form-box'>
            <Form.Item field='incidentDetails'>
              <Input
                allowClear
                prefix={<IconSearch />}
                placeholder={t('incidentReport:filters.incidentDetails')}
                style={{ width: 220 }}
              />
            </Form.Item>
            <Form.Item field='locationSystem'>
              <Input
                allowClear
                prefix={<IconSearch />}
                placeholder={t('incidentReport:filters.locationSystem')}
                style={{ width: 220 }}
              />
            </Form.Item>
            <Form.Item field='status'>
              <Select
                allowClear
                placeholder={t('incidentReport:filters.status')}
                options={statusOptions}
                style={{ width: 180 }}
              />
            </Form.Item>
            <Form.Item field='covertToAccident'>
              <Select
                allowClear
                placeholder={t('incidentReport:filters.convertedToAccident')}
                options={convertedOptions}
                style={{ width: 200 }}
              />
            </Form.Item>
          </div>
        </ListFilterHseForm>
      </div>
      <div className={`${classPrefix}-table`}>
        <UnifiedTableStyle
          ref={tableRef}
          rowKey='incidentReportId'
          columns={columns}
          getList={getList}
          showNoColumn={false}
          loading={true}
          showPagination={true}
          border={true}
        />
      </div>
      <DeleteConfirmModal
        visible={deleteVisible}
        loading={incidentDeleteLoading}
        onOk={() => handleDeleteOk()}
        onCancel={() => {
          setDeleteVisible(false)
          deleteIdRef.current = null
        }}
      />
      <Modal
        visible={reportNewIncidentVisible}
        onCancel={() => {
          newIncidentForm.resetFields()
          setEmergencyLocation('')
          setReportNewIncidentVisible(false)
        }}
        title={t('incidentReport:modalTitle')}
        className='incident-report-modal'
        footer={
          <div className='incident-report-modal-footer'>
            <Button
              onClick={() => {
                newIncidentForm.resetFields()
                setEmergencyLocation('')
                setReportNewIncidentVisible(false)
              }}
            >
              {t('common:btn.cancel')}
            </Button>
            <Button
              type='primary'
              onClick={() => handleOk()}
              loading={saveIncidentReportLoading}
            >
              {t('common:btn.submit')}
            </Button>
          </div>
        }
      >
        <Form layout='vertical' form={newIncidentForm}>
          <Row>
            <Col span={24}>
              <FormItem
                label={t('incidentReport:columns.incidentDateTime')}
                field={'incidentDate'}
                rules={[
                  {
                    required: true,
                    message: t('common:pleaseSelect'),
                  },
                ]}
              >
                <DatePicker
                  format='DD/MM/YYYY HH:mm'
                  showTime
                  style={{ width: '100%' }}
                  placeholder={t('common:pleaseSelect')}
                  getPopupContainer={() => document.body}
                />
              </FormItem>
            </Col>
            <Col span={24}>
              <FormItem
                label={t('incidentReport:form.emergencyLocation')}
                field={'locationType'}
                rules={[
                  {
                    required: true,
                    message: t('common:pleaseSelect'),
                  },
                ]}
              >
                <RadioGroup
                  onChange={(val) => {
                    setEmergencyLocation(val)
                    if (val !== 'insideBuilding') {
                      newIncidentForm.setFieldValue('floorOfEmergency', [])
                    }
                  }}
                >
                  <Radio value={EmergencyLocation.OutOfTheBuilding}>
                    {t('incidentReport:form.outOfBuilding')}
                  </Radio>
                  <Radio value={EmergencyLocation.InsideTheBuilding}>
                    {t('incidentReport:form.insideBuilding')}
                  </Radio>
                </RadioGroup>
              </FormItem>
            </Col>
            {emergencyLocation == EmergencyLocation.InsideTheBuilding && (
              <Col span={24}>
                <FormItem
                  label={t('incidentReport:form.floorOfEmergency')}
                  field={'floors'}
                  rules={[
                    {
                      required: true,
                      message: t('common:pleaseSelect'),
                      validator: (val, cb) => {
                        if (!val || val.length === 0) {
                          cb(t('common:pleaseSelect'))
                        } else {
                          cb()
                        }
                      },
                    },
                  ]}
                >
                  <FloorSelector />
                </FormItem>
              </Col>
            )}
          </Row>
        </Form>
      </Modal>
    </div>
  )
}

export default IncidentReport

