import './index.less'
import { useCallback, useMemo, useRef, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { useNavigate } from 'react-router-dom'
import { useRequest } from 'ahooks'
import {
  Alert,
  Badge,
  Button,
  DatePicker,
  Form,
  Input,
  Select,
  Space,
} from '@arco-design/web-react'
import type { TableColumnProps } from '@arco-design/web-react'
import {
  IconExclamationCircle,
  IconEye,
  IconSearch,
  IconStamp,
} from '@arco-design/web-react/icon'
import { renderEllipsisText } from '@common/components/EllipsisText'
import FullScreenTableSection from '@common/components/FullScreenTableSection'
import ListFilterHseForm from '@common/components/ListFilterHseForm'
import PageWrapper from '@common/components/PageWrapper'
import UnifiedTableStyle from '@common/components/UnifiedTableStyle'
import { tableHeaderCellStyle } from '@/constants/table'
import { getSecurityPatrolPageRequest } from '@/service'
import { handelFieldNameShow } from '@/utils/tools.ts'
import type {
  PatrolPageItem,
  PatrolPageResponse,
  SecurityPatrolPageFilterValues,
  SecurityPatrolPageParams,
  SecurityPatrolRecordRow,
  SecurityPatrolStatus,
} from '@/types/securityPatrol'

const classPrefix = 'security-patrol-records'

const statusColorMap: Record<SecurityPatrolStatus, string> = {
  draft: 'gray',
  underReview: 'orangered',
  approved: 'green',
  rejected: 'red',
}

const PATROL_STATUS_CODE = {
  DRAFT: 0,
  UNDER_REVIEW: 1,
  APPROVED: 2,
  REJECTED: 3,
} as const

const PATROL_STATUS_CODE_TO_KEY: Record<number, SecurityPatrolStatus> = {
  [PATROL_STATUS_CODE.DRAFT]: 'draft',
  [PATROL_STATUS_CODE.UNDER_REVIEW]: 'underReview',
  [PATROL_STATUS_CODE.APPROVED]: 'approved',
  [PATROL_STATUS_CODE.REJECTED]: 'rejected',
}

const SHIFT_CODE_TO_KEY = {
  1: 'day',
  2: 'night',
} as const

const formatPatrolDateParam = (value?: unknown) => {
  if (!value) return undefined
  if (typeof value === 'string') {
    if (value.includes('/')) return value
    const [year, month, day] = value.split('-')
    return year && month && day ? `${day}/${month}/${year}` : value
  }
  const formatter = value as { format?: (format: string) => string }
  return typeof formatter.format === 'function'
    ? formatter.format('DD/MM/YYYY')
    : undefined
}

const toPatrolRecordRow = (item: PatrolPageItem): SecurityPatrolRecordRow => ({
  patrolId: item.patrolId,
  patrolDate: item.patrolDate,
  shift: SHIFT_CODE_TO_KEY[item.shift as keyof typeof SHIFT_CODE_TO_KEY],
  inspector: item.inspector,
  inspectorName: item.inspectorName || '',
  inspectorNameAr: item.inspectorNameAr,
  status: PATROL_STATUS_CODE_TO_KEY[item.status ?? 0] || 'draft',
  statusCode: item.status,
  issuesObserved: item.issuesObserved,
  code: item.code,
})

const SecurityPatrolRecords = () => {
  const { t } = useTranslation(['securityPatrol', 'common'])
  const navigate = useNavigate()
  const tableRef = useRef<any>(null)
  const filtersRef = useRef<SecurityPatrolPageFilterValues>({})
  const [, setFilters] = useState<SecurityPatrolPageFilterValues>({})

  const { runAsync: runPatrolPage } = useRequest(getSecurityPatrolPageRequest, {
    manual: true,
  })

  const statusOptions = useMemo(
    () => [
      {
        label: t('securityPatrol:status.draft'),
        value: PATROL_STATUS_CODE.DRAFT,
      },
      {
        label: t('securityPatrol:status.underReview'),
        value: PATROL_STATUS_CODE.UNDER_REVIEW,
      },
      {
        label: t('securityPatrol:status.approved'),
        value: PATROL_STATUS_CODE.APPROVED,
      },
      {
        label: t('securityPatrol:status.rejected'),
        value: PATROL_STATUS_CODE.REJECTED,
      },
    ],
    [t],
  )

  const getList = useCallback(
    async (params?: SecurityPatrolPageParams) => {
      const pageNum = params?.pageNum || 1
      const pageSize = params?.pageSize || 10
      const filters = filtersRef.current
      const req = {
        pageNum,
        pageSize,
        status: filters.status,
        shift: filters.shift,
        keyword: filters.keyword,
        startDate: filters.patrolDate?.startTime,
        endDate: filters.patrolDate?.endTime,
      }

      try {
        const res = (await runPatrolPage(req)) as PatrolPageResponse
        return {
          list: (res?.list || []).map(toPatrolRecordRow),
          total: res?.total || 0,
          pageNum,
          pageSize,
        }
      } catch {
        return {
          list: [],
          total: 0,
          pageNum,
          pageSize,
        }
      }
    },
    [runPatrolPage],
  )

  const handleSubmit = (values: SecurityPatrolPageFilterValues) => {
    const nextFilters = values || {}
    filtersRef.current = nextFilters
    setFilters(nextFilters)
    tableRef.current?.setPageNum?.(1)
    tableRef.current?.refresh?.()
  }

  const handleReset = () => {
    filtersRef.current = {}
    setFilters({})
    tableRef.current?.setPageNum?.(1)
    tableRef.current?.refresh?.()
  }

  const columns: TableColumnProps<SecurityPatrolRecordRow>[] = useMemo(
