// selectFloor string key → { type, floor } for API
// keys: 'around' | 'inside-{0..8}' | 'parking-{9..11}'
const resolveTypeAndFloorCode = (
  key: string,
): { type: number; floor: number } => {
  if (key === 'around') return { type: PatrolFormSetupTypeEnum.Around, floor: -1 }
  if (key.startsWith('inside-'))
    return { type: PatrolFormSetupTypeEnum.Inside, floor: parseInt(key.slice(7)) }
  if (key.startsWith('parking-'))
    return { type: PatrolFormSetupTypeEnum.Parking, floor: parseInt(key.slice(8)) }
  return { type: PatrolFormSetupTypeEnum.Around, floor: -1 }
}

