const formatDisplayDate = (value?: string | null) => {
  if (!value) return '-'
  const datePart = value.split('T')[0]
  const [year, month, day] = datePart.split('-')
  return year && month && day ? `${day}/${month}/${year}` : value
}

const mapDetailResponse = (
  resp: PatrolDetailResponse,
  statusFallback: SecurityPatrolStatus,
  summaries?: PatrolTabSummaryResponseItem[],
): PatrolDetailViewData => {
  const tabSummaries = summaries || []
  const floorSummaries: SecurityPatrolFloorSummary[] = []
  tabSummaries.forEach((tab) => {
    ;(tab.floorSummaryList || []).forEach((f) => floorSummaries.push(f))
  })

  return {
    patrolId: resp.patrolId,
    patrolDate: resp.patrolDate,
    shift: SHIFT_CODE_TO_KEY[resp.shift || 0],
    inspector: resp.inspector,
    inspectorName: resp.inspectorName,
    inspectorNameAr: resp.inspectorNameAr,
    contractorName: resp.reportedByName,
    contractorNameAr: resp.reportedByNameAr,
    status: statusFallback,
    currentAnswers: resp.patrolAnswerList || [],
    code: resp.code,
    tabSummaries,
    floorSummaries,
  }
}

const buildCategories = (
  answers: SecurityPatrolAnswerDto[],
): PatrolChecklistCategoryViewData[] => {
  const categoryMap = new Map<string, PatrolChecklistCategoryViewData>()

  answers.forEach((answer) => {
    const categoryKey = String(answer.sectionId ?? 'unsectioned')
    let category = categoryMap.get(categoryKey)
    if (!category) {
      category = {
        id: categoryKey,
        sectionId: answer.sectionId,
        sectionName: answer.sectionName,
        sectionNameAr: answer.sectionNameAr,
        defaultOpen: categoryMap.size === 0,
        items: [],
      }
      categoryMap.set(categoryKey, category)
    }

    category.items.push({
      id: String(answer.patrolAnswerId),
      itemId: answer.itemId,
      itemName: answer.itemName,
      itemNameAr: answer.itemNameAr,
      answer: IS_SITUATION_TO_ANSWER[answer.isSituation ?? -1] || 'na',
      findings: answer.findings || [],
    })
  })

  return Array.from(categoryMap.values())
}

