const AttachmentThumb = ({
  attachment,
  index,
  onPreview,
}: {
  attachment: SecurityPatrolAttachment
  index: number
  onPreview: (preview: PreviewImage) => void
}) => {
  const [previewUrl, setPreviewUrl] = useState('')
  const requestUrl = attachment.url || attachment.absUrl || ''
  const fileType = attachment.fileType || attachment.contentType

  useEffect(() => {
    let canceled = false
    let objectUrl = ''

    setPreviewUrl('')

    const loadPreview = async () => {
      if (!requestUrl) return

      try {
        const response: any = await downloadFileByUrl(
          requestUrl,
          attachment.fileName,
          fileType,
        )
        const blobData = response?.data
        if (!blobData) return

        const contentType = response?.headers?.['content-type']
        const blob =
          blobData instanceof Blob
            ? blobData
            : new Blob([blobData], { type: contentType })

        objectUrl = URL.createObjectURL(blob)
        if (canceled) {
          URL.revokeObjectURL(objectUrl)
          return
        }

        setPreviewUrl(objectUrl)
      } catch {
        setPreviewUrl('')
      }
    }

    void loadPreview()

    return () => {
      canceled = true
      if (objectUrl) {
        URL.revokeObjectURL(objectUrl)
      }
    }
  }, [attachment.fileName, fileType, requestUrl])

  if (!previewUrl) {
    return (
      <span
        title={attachment.fileName}
        className={`${classPrefix}__thumb ${classPrefix}__thumb--${
          (index % 3) + 1
        }`}
      />
    )
  }

  return (
    <button
      type='button'
      title={attachment.fileName}
      className={`${classPrefix}__thumb ${classPrefix}__thumb--image`}
      onClick={() =>
        onPreview({
          url: previewUrl,
          fileName: attachment.fileName,
        })
      }
    >
      <img src={previewUrl} alt={attachment.fileName || ''} />
    </button>
  )
}

