          { key: 'inside-6', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: '5' }), issueCount: floorIssueMap.get('2-6') ?? 0 },
          { key: 'inside-7', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: '6' }), issueCount: floorIssueMap.get('2-7') ?? 0 },
          { key: 'inside-8', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: 'RF' }), issueCount: floorIssueMap.get('2-8') ?? 0 },
        ],
      },
      parking: {
        issueCount: tabIssueMap.get(3) ?? 0,
        floors: [
          { key: 'parking-9',  label: 'P1', issueCount: floorIssueMap.get('3-9')  ?? 0 },
          { key: 'parking-10', label: 'P2', issueCount: floorIssueMap.get('3-10') ?? 0 },
          { key: 'parking-11', label: 'P3', issueCount: floorIssueMap.get('3-11') ?? 0 },
        ],
      },
    }
  }, [tabSummaries, t])

  const currentCategories = useMemo(() => {
    if (!detail) return []
    return buildCategories(detail.currentAnswers || [])
  }, [detail])

  const fetchApproveDetail = useCallback(async () => {
    if (!patrolRecordId) return
    try {
      const res = (await runPatrolApproveDetail({
        patrolId: patrolRecordId,
      })) as PatrolApproveDetailResponse
      setApproveLog(res?.approveList || [])
      setApproveFlag(res?.approveFlag || 0)
    } catch {
      setApproveLog([])
      setApproveFlag(0)
    }
  }, [patrolRecordId, runPatrolApproveDetail])


  // 首次进入：拉 finding/count 汇总 + 审批详情
  useEffect(() => {
    if (!patrolRecordId) return
    const init = async () => {
      try {
        const summaries = (await runPatrolFindingCount({
          patrolId: patrolRecordId,
        })) as PatrolTabSummaryResponseItem[]
        setTabSummaries(summaries || [])
      } catch {
        setTabSummaries([])
      }
    }
    void init()
    void fetchApproveDetail()
  }, [patrolRecordId, runPatrolFindingCount, fetchApproveDetail])

  // 切换 tab/floor：按 type+floor 重新拉取 detail
  useEffect(() => {
    if (!patrolRecordId) return
    const { type, floor } = resolveTypeAndFloorCode(selectFloor)
    const fetchDetail = async () => {
      try {
        const res = (await runPatrolDetail({
          patrolId: patrolRecordId,
          type,
          floor,
        })) as PatrolDetailResponse
        const fallback = getStatusFromParam(statusParam) || 'draft'
        setDetail(mapDetailResponse(res, fallback, tabSummaries))
      } catch {
        setDetail(null)
      }
    }
    void fetchDetail()
  }, [patrolRecordId, runPatrolDetail, selectFloor, statusParam, tabSummaries])

  const handleBack = () => {
    navigate('/security-patrol/patrol-records')
  }

  return (
    <PageWrapper
      showBreadcrumb
      routes={breadcrumbRoutes}
      resetMarginTop
      headerTitle={<HeaderTitle status={currentStatus} />}
      pageClassName={`${classPrefix}-page`}
    >
      <Spin
        className={`${classPrefix}__spin`}
        loading={detailLoading || approveDetailLoading}
        style={{ width: '100%' }}
      >
        <div className={classPrefix}>
          <div className={`${classPrefix}__layout`}>
            <div className={`${classPrefix}__main`}>
              <div className={`${classPrefix}__meta`}>
                <div className={`${classPrefix}__meta-item`}>
                  <div className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.detail.patrolId')}
                  </div>
                  <div className={`${classPrefix}__meta-value`}>
                    {detail?.code || '-'}
                  </div>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <div className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.detail.patrolDate')}
                  </div>
                  <div className={`${classPrefix}__meta-value`}>
                    {detail?.patrolDate || '-'}
                  </div>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <div className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.columns.shift')}
                  </div>
                  <div className={`${classPrefix}__meta-value`}>
                    {detail?.shift
                      ? t(`securityPatrol:shift.${detail.shift}`)
                      : '-'}
                  </div>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <div className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.columns.contractor')}
                  </div>
                  <div className={`${classPrefix}__meta-value`}>
                    {renderEllipsisText(
                      safeFieldText(
                        detail?.contractorName,
                        detail?.contractorNameAr,
                      ),
                    )}
                  </div>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <div className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.detail.patrollerName')}
                  </div>
                  <div className={`${classPrefix}__meta-value`}>
                    {renderEllipsisText(
                      detail?.inspector ? detail.inspector : '-',
                    )}
                  </div>
                </div>
              </div>

              <div className={`${classPrefix}__main-content`}>
                <div className={`${classPrefix}__main-content-tabs`}>
                  {/* Around the Building */}
                  <div
                    className={classNames(
                      `${classPrefix}__main-content-tabs-item`,
                      { select: selectFloor === 'around' },
                    )}
                    onClick={() => setSelectFloor('around')}
                  >
                    <div className={`${classPrefix}__main-content-tabs-item-title`}>
                      {t('securityPatrol:patrolRecords.detail.tabs.around')}
                    </div>
                    {!!navData.around.issueCount && (
                      <div className={`${classPrefix}__main-content-tabs-item-issueCount`}>
                        {navData.around.issueCount}
                      </div>
                    )}
                  </div>

                  {/* Inside the Building group header */}
                  <div
                    className={`${classPrefix}__main-content-tabs-item`}
                    onClick={() => setSelectFloor('inside-0')}
                  >
                    <div className={`${classPrefix}__main-content-tabs-item-title`}>
                      {t('securityPatrol:patrolRecords.detail.tabs.inside')}
                    </div>
                    {!!navData.inside.issueCount && (
                      <div className={`${classPrefix}__main-content-tabs-item-issueCount`}>
                        {navData.inside.issueCount}
                      </div>
                    )}
                  </div>
                  {navData.inside.floors.map((floor) => (
                    <div
                      key={floor.key}
                      className={classNames(
                        `${classPrefix}__main-content-tabs-item`,
                        'second-level',
                        { select: selectFloor === floor.key },
                      )}
                      onClick={() => setSelectFloor(floor.key)}
                    >
                      <div className={`${classPrefix}__main-content-tabs-item-title`}>
                        {floor.label}
                      </div>
                      {!!floor.issueCount && (
                        <div className={`${classPrefix}__main-content-tabs-item-issueCount`}>
                          {floor.issueCount}
                        </div>
                      )}
                    </div>
                  ))}

                  {/* Parking group header */}
                  <div
                    className={`${classPrefix}__main-content-tabs-item`}
                    onClick={() => setSelectFloor('parking-9')}
                  >
                    <div className={`${classPrefix}__main-content-tabs-item-title`}>
                      {t('securityPatrol:patrolRecords.detail.tabs.parking')}
                    </div>
                    {!!navData.parking.issueCount && (
                      <div className={`${classPrefix}__main-content-tabs-item-issueCount`}>
                        {navData.parking.issueCount}
                      </div>
                    )}
                  </div>
                  {navData.parking.floors.map((floor) => (
                    <div
                      key={floor.key}
                      className={classNames(
                        `${classPrefix}__main-content-tabs-item`,
                        'second-level',
                        { select: selectFloor === floor.key },
                      )}
                      onClick={() => setSelectFloor(floor.key)}
                    >
                      <div className={`${classPrefix}__main-content-tabs-item-title`}>
                        {floor.label}
                      </div>
                      {!!floor.issueCount && (
                        <div className={`${classPrefix}__main-content-tabs-item-issueCount`}>
                          {floor.issueCount}
                        </div>
                      )}
                    </div>
                  ))}
                </div>

                <div className={`${classPrefix}__categories`}>
                  {currentCategories.map((category, index) => (
                    <CategorySection
                      key={`${category.id}`}
                      category={category}
                      index={index}
                    />
                  ))}
                  {!currentCategories.length && (
                    <div className={`${classPrefix}__empty`}>
                      <NoData />
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className={`${classPrefix}__side`}>
              <ApprovalProgressCard
                title={t('securityPatrol:patrolRecords.detail.reviewTitle')}
                approvalRejected={rejectSecurityPatrolRequest}
                approvalApproved={approveSecurityPatrolRequest}
                approveLog={approveLog}
                approveFlag={approveFlag}
                backUrl={backUrl}
                moduleId={patrolRecordId}
                moduleIdKey='patrolId'
                submittedCardRows={[
                  {
                    label: t('securityPatrol:patrolRecords.detail.contractor'),
                    value:
                      handelFieldNameShow(
                        detail?.contractorName || '',
                        detail?.contractorNameAr || '',
                      ) || '-',
                  },
                  {
                    label: t('securityPatrol:patrolRecords.detail.patroller'),
                    value: detail?.inspector ? detail.inspector : '-',
                  },
                ]}
              />
            </div>
          </div>
        </div>
      </Spin>
      {showBackButton && (
        <div className={`${classPrefix}__footer`}>
          <Space size={12}>
            <Button icon={<IconArrowLeft />} onClick={handleBack}>
              {t('common:btn.back')}
            </Button>
          </Space>
        </div>
      )}
    </PageWrapper>
  )
}

export default PatrolRecordDetail

