import './index.less'
import { useCallback, useMemo, useRef, useState } from 'react'
import {
  Badge,
  Button,
  DatePicker,
  Form,
  Input,
  Link,
  Modal,
  Radio,
  Select,
  Space,
  Divider,
} from '@arco-design/web-react'
import type { TableColumnProps } from '@arco-design/web-react'
import {
  IconClose,
  IconEye,
  IconPen,
  IconPlus,
  IconUpload,
  IconDelete,
  IconSearch,
} from '@arco-design/web-react/icon'
import ContractorHeader from '../components/ContractorHeader'
import ListFilterHseForm from '@common/components/ListFilterHseForm'
import UnifiedTableStyle from '@common/components/UnifiedTableStyle'
import { renderEllipsisText } from '@common/components/EllipsisText'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import { tableHeaderCellStyle } from '@/constants/table'
import { useNavigate } from 'react-router-dom'
import { getPatrolList, savePatrol, deletePatrol } from '@/service'
import DeleteConfirmModal from '@common/components/DeleteConfirmModal'
import { useRequest } from 'ahooks'
import { ContractorApproval } from '@/constants/contractor'


// status: 0=Draft 1=UnderReview 2=Approved 3=Rejected
// shift:  1=Day   2=Night

interface PatrolRecordRow {
  patrolId: number
  patrolDate: string
  shift: number
  patrollerUserId: number
  patrollerUser: string
  status: number
  answerCount: number
  issuesObserved: number
  inspector: string
  reportTime: string
  patroller: any
}

interface PatrolRecordFilters {
  status?: number
  patrolDate?: { startTime?: string; endTime?: string }
  shift?: any
  patroller?: any
}

const classPrefix = 'contractor-patrol-record'

const statusColorMap: Record<number, string> = {
  0: '#86909C',
  1: '#FF7D00',
  2: '#45AD5E',
  3: '#F53F3F',
}

const statusTextMap: Record<number, string> = {
  0: 'Draft',
  1: 'Under Review',
  2: 'Approved',
  3: 'Rejected',
}

const shiftTextMap: Record<number, string> = {
  1: 'Day',
  2: 'Night',
}

interface AddPatrolFormValues {
  shift: number
  patrollerName: string
  patrolDate?: string
}

const today = new Date().toISOString().slice(0, 10)

const PatrolRecord = () => {
  const navigate = useNavigate()
  const tableRef = useRef<any>(null)
  const [filters, setFilters] = useState<PatrolRecordFilters>({})
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const [addModalVisible, setAddModalVisible] = useState(false)
  const [deleteModalVisible, setDeleteModalVisible] = useState(false)
  const [pendingDeleteId, setPendingDeleteId] = useState<number | null>(null)
  const [addForm] = Form.useForm<AddPatrolFormValues>()
  const formDataRef = useRef<AddPatrolFormValues | null>(null)

  const statusOptions = useMemo(
    () => [
      { label: 'Draft', value: 0 },
      { label: 'Under Review', value: 1 },
      { label: 'Approved', value: 2 },
      { label: 'Rejected', value: 3 },
    ],
    [],
  )

  const getList = useCallback(
    async (params?: { pageNum?: number; pageSize?: number }) => {
      const pageNum = params?.pageNum || 1
      const pageSize = params?.pageSize || 20

      const res: any = await getPatrolList({
        pageNum,
        pageSize,
        keyword: filters.patroller ?? undefined,
        status: filters.status ?? undefined,
        startDate: filters.patrolDate?.startTime || undefined,
        endDate: filters.patrolDate?.endTime || undefined,
      })

      const list: PatrolRecordRow[] = res?.list || []
      const total: number = res?.total || 0

      return { list, total, pageNum, pageSize }
    },
    [filters],
  )

  const handleSubmit = (values: PatrolRecordFilters) => {
    setFilters(values || {})
    tableRef.current?.setPageNum?.(1)
    tableRef.current?.refresh?.()
  }

  const handleReset = () => {
    setFilters({})
    tableRef.current?.setPageNum?.(1)
    tableRef.current?.refresh?.()
  }

  const columns: TableColumnProps<PatrolRecordRow>[] = useMemo(
    () => [
      {
        title: 'Patrol ID',
        dataIndex: 'code',
        width: 160,
        headerCellStyle: tableHeaderCellStyle,
      },
      {
        title: 'Patrol Date',
        dataIndex: 'patrolDate',
        width: 160,
        headerCellStyle: tableHeaderCellStyle,
      },
      {
        title: 'Shift',
        dataIndex: 'shift',
        width: 120,
        headerCellStyle: tableHeaderCellStyle,
        render: (value: number) => shiftTextMap[value] ?? value,
      },
      {
        title: 'Patroller',
        dataIndex: 'inspector',
        width: 120,
        headerCellStyle: tableHeaderCellStyle,
        render: (_, record) => {
          return renderEllipsisText(record?.inspector)
        },
      },
      {
        title: 'Issues',
        dataIndex: 'issuesObserved',
        width: 100,
        headerCellStyle: tableHeaderCellStyle,
      },
      {
        title: 'Status',
        dataIndex: 'status',
        width: 110,
        headerCellStyle: tableHeaderCellStyle,
        render: (value: number) => (
          <Badge
            color={statusColorMap[value] ?? '#86909C'}
            text={statusTextMap[value] ?? '-'}
          />
        ),
      },
      {
        title: 'Last Updated',
        dataIndex: 'lastUpdatedTime',
        width: 150,
        headerCellStyle: tableHeaderCellStyle,
        render: (_, record) => {
          return renderEllipsisText(record?.reportTime)
        },
      },
      {
        title: 'Actions',
        dataIndex: 'actions',
        width: 80,
        fixed: 'right',
        headerCellStyle: tableHeaderCellStyle,
        render: (_value, record) => {
          // const isEditable = record.status === 0 || record.status === 3
          const isEditable = record.status
          return (
            <div className='patrol-record-actions'>
              {
                <Link
                  icon={
                    isEditable == ContractorApproval.Open ? (
                      <IconPen />
                    ) : (
                      <IconEye />
                    )
                  }
                  className='coc-table-link'
                  onClick={() =>
                    isEditable == ContractorApproval.Open
                      ? navigate(`/contractor/addOrEdit/${record?.patrolId}`)
                      : isEditable != ContractorApproval.Open
                        ? navigate(`/contractor/detail/${record?.patrolId}`, {
                            state: {
                              status: record?.status,
                            },
                          })
                        : null
                  }
                ></Link>
              }
              <Divider type='vertical' className='actions-divider' />

              <Link
                icon={<IconDelete />}
                className='coc-table-link'
                onClick={() => handleDelete(record?.patrolId)}
                disabled={record.status != ContractorApproval.Open}
              ></Link>
            </div>
          )
        },
      },
    ],
    [isLanguageAR, navigate],
  )

  const { loading: deleteLoading, run: runDelete } = useRequest(deletePatrol, {
    manual: true,
    onSuccess: () => {
      setDeleteModalVisible(false)
      setPendingDeleteId(null)
      tableRef.current?.refresh?.()
    },
    onError: () => {
      setDeleteModalVisible(false)
      setPendingDeleteId(null)
    },
  })

  const handleDelete = (patrolId: number) => {
    setPendingDeleteId(patrolId)
    setDeleteModalVisible(true)
  }

  const handleDeleteConfirm = () => {
    if (pendingDeleteId !== null) {
      runDelete({ patrolId: pendingDeleteId })
    }
  }

  const handleDeleteCancel = () => {
    setDeleteModalVisible(false)
    setPendingDeleteId(null)
  }

  const { run: runPatrolId, loading: getPatrolIdLoading } = useRequest(
    savePatrol,
    {
      manual: true,
      onSuccess: (res: any) => {
        navigate(`/contractor/addOrEdit/${res}`, { state: formDataRef.current })
        setAddModalVisible(false)
        addForm.resetFields()
      },
    },
  )

  const addPatrol = () => {
    setAddModalVisible(true)
  }

  const handleAddConfirm = () => {
    addForm.validate().then((values) => {
      formDataRef.current = { ...values, patrolDate: today }
      const data = formDataRef.current
      runPatrolId(data)
    })
  }

  const handleAddCancel = () => {
    setAddModalVisible(false)
    addForm.resetFields()
  }
  return (
    <div className={classPrefix}>
      <ContractorHeader />
      <div className={`${classPrefix}__content`}>
        <ListFilterHseForm
          showKeywordInput={false}
          onSubmit={handleSubmit}
          onReset={handleReset}
          renderBtnJsx={
            <Button type='primary' icon={<IconPlus />} onClick={addPatrol}>
              Add Patrol Record
            </Button>
          }
        >
          <div className='search-form-box'>
            <Form.Item field='patroller'>
              <Input
                allowClear
                prefix={<IconSearch />}
                placeholder={'Search Patroller'}
                style={{ width: 220 }}
              />
            </Form.Item>
            <Form.Item field='status'>
              <Select
                allowClear
                placeholder='Select Status'
                options={statusOptions}
                style={{ width: 180 }}
              />
            </Form.Item>
            <Form.Item
              field='patrolDate'
              normalize={(value) => ({
                startTime: value?.[0],
                endTime: value?.[1],
              })}
              formatter={(value) =>
                value?.startTime ? [value.startTime, value.endTime] : []
              }
            >
              <DatePicker.RangePicker
                format='YYYY-MM-DD'
                placeholder={['Date From', 'Date To']}
                style={{ width: 260 }}
              />
            </Form.Item>
          </div>
        </ListFilterHseForm>
        <div className={`${classPrefix}__table`}>
          <UnifiedTableStyle
            ref={tableRef}
            rowKey='securityPatrolId'
            columns={columns}
            getList={getList}
            showNoColumn={false}
            showPagination={true}
            border={true}
            tableHeight={40}
          />
        </div>
      </div>

      <DeleteConfirmModal
        visible={deleteModalVisible}
        loading={deleteLoading}
        onOk={handleDeleteConfirm}
        onCancel={handleDeleteCancel}
      />

      <Modal
        title='Add Patrol Record'
        visible={addModalVisible}
        onCancel={handleAddCancel}
        footer={
          <Space>
            <Button icon={<IconClose />} onClick={handleAddCancel}>
              Cancel
            </Button>
            <Button
              type='primary'
              icon={<IconUpload />}
              loading={getPatrolIdLoading}
              onClick={handleAddConfirm}
            >
              Confirm
            </Button>
          </Space>
        }
      >
        <Form form={addForm} layout='vertical' initialValues={{ shift: 1 }}>
          <Form.Item label='Patrol Date'>
            <Input value={today} disabled />
          </Form.Item>
          <Form.Item
            field='shift'
            label='Shift'
            rules={[{ required: true, message: 'Please select a shift' }]}
          >
            <Radio.Group>
              <Radio value={1}>Day</Radio>
              <Radio value={2}>Night</Radio>
            </Radio.Group>
          </Form.Item>
          <Form.Item
            field='inspector'
            label='Patroller Name'
            rules={[{ required: true, message: 'Please enter patroller name' }]}
          >
            <Input placeholder='Enter patroller name' />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  )
}

export default PatrolRecord

import './index.less'
import { useEffect, useMemo, useState } from 'react'
import { Button, Image } from '@arco-design/web-react'
import {
  IconDown,
  IconEdit,
  IconLeft,
  IconUp,
} from '@arco-design/web-react/icon'
import ContractorHeader from '../../../components/ContractorHeader'
import ApprovalProgressCard from '@common/components/ApprovalProgressCard'
import { useParams, useNavigate } from 'react-router-dom'
import {
  getPatrolApprovalRecord,
  getPatrolDetail,
  patrolFindingCount,
} from '@/service'
import { useRequest } from 'ahooks'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import { useLocation } from 'react-router-dom'
import { ContractorApproval } from '@/constants/contractor'
import { useTranslation } from 'react-i18next'
// ─── Types ────────────────────────────────────────────────────────────────────

type Answer = 1 | 0 | null

interface AttachmentItem {
  url: string
  absUrl?: string
  name: string
}

interface Finding {
  id: string
  notesAr: string
  notesEn: string
  attachments: AttachmentItem[]
  correctiveActionAr: string
  correctiveActionEn: string
  dept: string
  targetClosureDate: string
}

interface QuestionItem {
  id: string
  question: string
  answer: Answer
  findings: Finding[]
}

interface Section {
  id: string
  no: number
  title: string
  defaultOpen: boolean
  items: QuestionItem[]
}

const INSIDE_FLOORS = [
  { label: 'G', value: 0 },
  { label: 'M', value: 1 },
  { label: '1', value: 2 },
  { label: '2', value: 3 },
  { label: '3', value: 4 },
  { label: '4', value: 5 },
  { label: '5', value: 6 },
  { label: '6', value: 7 },
  { label: 'RF', value: 8 },
] as const
type FloorKey = (typeof INSIDE_FLOORS)[number]

const PARKING_SUBS = [
  { label: 'P1', value: 9 },
  { label: 'P2', value: 10 },
  { label: 'P3', value: 11 },
] as const
type ParkingKey = (typeof PARKING_SUBS)[number]

type NavSel =
  | { area: 'around' }
  | { area: 'inside'; floor: FloorKey }
  | { area: 'parking'; sub: ParkingKey }

// ─── Constants ────────────────────────────────────────────────────────────────

const classPrefix = 'ratrol-record-detail'

// ─── Approval mock data (右侧审批暂不对接) ────────────────────────────────────

// ─── AnswerBadge ──────────────────────────────────────────────────────────────

const AnswerBadge = ({ answer }: { answer: Answer }) => (
  <div
    className={`${classPrefix}__answer-badge ${classPrefix}__answer-badge--${
      answer === 1 ? 'yes' : answer === 0 ? 'no' : ''
    }`}
  >
    {answer === 1 ? 'Yes' : answer === 0 ? 'No' : '--'}
  </div>
)

// ─── FindingView ──────────────────────────────────────────────────────────────

const FindingView = ({
  finding,
  index,
}: {
  finding: Finding
  index: number
}) => (
  <div className={`${classPrefix}__finding`}>
    <div className={`${classPrefix}__finding-title`}>FINDING {index + 1}</div>

    <div className={`${classPrefix}__field`}>
      <span className={`${classPrefix}__field-label`}>Notes/Remarks</span>
      <span className={`${classPrefix}__field-value`}>
        {finding.notesEn || finding.notesAr || '--'}
      </span>
    </div>

    <div className={`${classPrefix}__field`}>
      <span className={`${classPrefix}__field-label`}>Attachment</span>
      <div className={`${classPrefix}__attachments`}>
        {finding.attachments.length > 0
          ? finding.attachments.map((att, idx) => {
              const src = att.absUrl || att.url
              return src ? (
                <Image
                  key={idx}
                  src={src}
                  alt={att.name}
                  width={72}
                  height={72}
                  className={`${classPrefix}__attachment-img`}
                />
              ) : (
                <div
                  key={idx}
                  className={`${classPrefix}__attachment-placeholder`}
                />
              )
            })
          : '--'}
      </div>
    </div>

    <div className={`${classPrefix}__field`}>
      <span className={`${classPrefix}__field-label`}>Corrective Actions</span>
      <span className={`${classPrefix}__field-value`}>
        {finding.correctiveActionEn || finding.correctiveActionAr || '--'}
      </span>
    </div>

    <div className={`${classPrefix}__finding-row`}>
      <div className={`${classPrefix}__field`}>
        <span className={`${classPrefix}__field-label`}>
          Responsible Department
        </span>
        <span className={`${classPrefix}__field-value`}>
          {finding.dept || '--'}
        </span>
      </div>
      <div className={`${classPrefix}__field`}>
        <span className={`${classPrefix}__field-label`}>
          Target Closure Date
        </span>
        <span className={`${classPrefix}__field-value`}>
          {finding.targetClosureDate || '--'}
        </span>
      </div>
    </div>
  </div>
)

// ─── QuestionItemView ─────────────────────────────────────────────────────────

const QuestionItemView = ({ item }: { item: QuestionItem }) => (
  <div className={`${classPrefix}__item`}>
    <div className={`${classPrefix}__item-row`}>
      <span className={`${classPrefix}__item-question`}>{item.question}</span>
      <AnswerBadge answer={item.answer} />
    </div>
    {item.answer === 0 && item.findings.length > 0 && (
      <div className={`${classPrefix}__findings`}>
        {item.findings.map((f, idx) => (
          <FindingView key={f.id} finding={f} index={idx} />
        ))}
      </div>
    )}
  </div>
)

// ─── SectionView ──────────────────────────────────────────────────────────────

const SectionView = ({ section }: { section: Section }) => {
  const [open, setOpen] = useState(section.defaultOpen)

  return (
    <div className={`${classPrefix}__section`}>
      <div
        className={`${classPrefix}__section-header${open ? ` ${classPrefix}__section-header--open` : ''}`}
        onClick={() => setOpen((v) => !v)}
      >
        <div>
          <div className={`${classPrefix}__section-no`}>
            CATEGORY {section.no}
          </div>
          <div className={`${classPrefix}__section-title`}>{section.title}</div>
        </div>
        {open ? <IconUp /> : <IconDown />}
      </div>
      {open && section.items.length > 0 && (
        <div className={`${classPrefix}__section-body`}>
          {section.items.map((item) => (
            <QuestionItemView key={item.id} item={item} />
          ))}
        </div>
      )}
    </div>
  )
}

// ─── Main component ───────────────────────────────────────────────────────────

const PatrolRecordDetail = () => {
  const { id } = useParams()
  const navigate = useNavigate()
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const { t } = useTranslation(['common', 'incidentReport'])
  const [navSel, setNavSel] = useState<NavSel>({ area: 'around' })
  const [findingCountData, setFindingCountData] = useState<any>()
  const [detailData, setDetailData] = useState<any>(null)
  const [metaData, setMetaData] = useState<any>(null)
  const [approveLog, setApproveLog] = useState<any>([])
  const [approveFlag, setApproveFlag] = useState<number>(0)
  const location = useLocation()
  const { status } = location?.state
  // const {}
  // ─── Sidebar data derived from patrolFindingCount ─────────────────────────

  const aroundApiData = (findingCountData as any[] | undefined)?.find(
    (x: any) => x.type === 1,
  )
  const insideApiData = (findingCountData as any[] | undefined)?.find(
    (x: any) => x.type === 2,
  )
  const parkingApiData = (findingCountData as any[] | undefined)?.find(
    (x: any) => x.type === 3,
  )

  const getInsideFloorData = (floor: FloorKey) =>
    insideApiData?.floorSummaryList?.find(
      (f: any) => f.floorCode === floor.value,
    )

  const getParkingSubData = (sub: ParkingKey) =>
    parkingApiData?.floorSummaryList?.find(
      (f: any) => f.floorCode === sub.value,
    )

  // ─── Build sections dynamically from detail API ───────────────────────────

  const dynamicSections = useMemo((): Section[] => {
    const answerList: any[] = detailData?.patrolAnswerList ?? []
    if (!answerList.length) return []
    const map = new Map<string, Section>()
    answerList.forEach((ans: any) => {
      const key = String(ans.sectionId)
      if (!map.has(key)) {
        map.set(key, {
          id: `sec-${key}`,
          no: map.size + 1,
          title: isLanguageAR
            ? ans.sectionNameAr || ans.sectionName
            : ans.sectionName,
          defaultOpen: map.size === 0,
          items: [],
        })
      }
      const findings: Finding[] =
        ans.isSituation === 0 && ans.findings?.length
          ? ans.findings.map(
              (f: any): Finding => ({
                id: String(
                  f.correctiveActionId ?? `${ans.itemId}-${Math.random()}`,
                ),
                notesAr: f.findingRemarkAr ?? '',
                notesEn: f.findingRemark ?? '',
                attachments: (f.attachmentList ?? []).map((att: any) => ({
                  url: att.url ?? '',
                  absUrl: att.absUrl ?? '',
                  name: att.fileName ?? '',
                })),
                correctiveActionAr: f.correctiveActionAr ?? '',
                correctiveActionEn: f.correctiveAction ?? '',
                dept: isLanguageAR
                  ? f.org?.orgNameAr || f.org?.orgName || ''
                  : f.org?.orgName || '',
                targetClosureDate: f.targetClosureDate ?? '',
              }),
            )
          : []
      map.get(key)!.items.push({
        id: String(ans.itemId),
        question: isLanguageAR ? ans.itemNameAr || ans.itemName : ans.itemName,
        answer: ans.isSituation === 1 ? 1 : ans.isSituation === 0 ? 0 : null,
        findings,
      })
    })
    return Array.from(map.values())
  }, [detailData, isLanguageAR])

  const contentTitle =
    navSel.area === 'around'
      ? 'Around the Building'
      : navSel.area === 'inside'
        ? `Inside the Building - Floor ${navSel.floor.label}`
        : `Parking - ${navSel.sub.label}`

  // ─── API calls ────────────────────────────────────────────────────────────

  const { run: runPatrolFindingCount } = useRequest(patrolFindingCount, {
    manual: true,
    onSuccess: (res: any) => {
      setFindingCountData(res)
    },
  })

  const { run: runPatrolDetail } = useRequest(getPatrolDetail, {
    manual: true,
    onSuccess: (res: any) => {
      setDetailData(res)
      if (!metaData) setMetaData(res)
    },
  })
  const { run: runGetApprovalDetail } = useRequest(getPatrolApprovalRecord, {
    manual: true,
    onSuccess: (res: any) => {
      setApproveLog(res?.approveList || [])
      setApproveFlag(res?.approveFlag)
    },
  })

  useEffect(() => {
    if (id) {
      runPatrolFindingCount({ patrolId: id })
      runPatrolDetail({ patrolId: id, type: 1, floor: -1 })
      runGetApprovalDetail({ patrolId: id })
    }
  }, [id])

  const handleNavSel = (area: string, value?: any) => {
    let type = 1
    let floor = -1
    if (area === 'around') {
      setNavSel({ area: 'around' })
    } else if (area === 'inside') {
      setNavSel({ area: 'inside', floor: value })
      type = 2
      floor = value.value
    } else if (area === 'parking') {
      setNavSel({ area: 'parking', sub: value })
      type = 3
      floor = value.value
    }
    runPatrolDetail({ patrolId: id, type, floor })
  }
  const statusColorMap: Record<number, string> = {
    0: '#86909C',
    1: '#FF7D00',
    2: '#45AD5E',
    3: '#F53F3F',
  }
  const ApprovalType = {
    0: 'Draft',
    1: 'Under Review',
    2: 'Approved',
    3: 'Rejected',
  }

  return (
    <div className={classPrefix}>
      <ContractorHeader />

      <div className={`${classPrefix}__wrapper`}>
        <div className={`${classPrefix}__card`}>
          {/* Card header */}
          <div className={`${classPrefix}__card-header`}>
            <span className={`${classPrefix}__card-title`}>
              Security Patrol Detail
            </span>
            {status != null && (
              <div
                className={`${classPrefix}__status-badge`}
                style={{
                  borderColor: `${statusColorMap[status]}66`,
                  background: `${statusColorMap[status]}0D`,
                }}
              >
                <span
                  className={`${classPrefix}__status-badge-dot`}
                  style={{ background: statusColorMap[status] }}
                />
                <span
                  className={`${classPrefix}__status-badge-text`}
                  style={{ color: statusColorMap[status] }}
                >
                  {ApprovalType[status as keyof typeof ApprovalType] ?? '--'}
                </span>
              </div>
            )}
          </div>

          {/* Meta bar */}
          <div className={`${classPrefix}__meta-bar`}>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>Patrol ID</span>
              <span className={`${classPrefix}__meta-value`}>
                {metaData?.code ?? '--'}
              </span>
            </div>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>Patrol Date</span>
              <span className={`${classPrefix}__meta-value`}>
                {metaData?.patrolDate ?? '--'}
              </span>
            </div>

            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>Shift</span>
              <span className={`${classPrefix}__meta-value`}>
                {metaData?.shift === 1
                  ? 'Day'
                  : metaData?.shift === 2
                    ? 'Night'
                    : '--'}
              </span>
            </div>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>Contractor</span>
              <span className={`${classPrefix}__meta-value`}>
                {isLanguageAR
                  ? metaData?.reportedByNameAr
                  : metaData?.reportedByName}
              </span>
            </div>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>
                Patroller Name
              </span>
              <span className={`${classPrefix}__meta-value`}>
                {metaData?.inspector ?? '--'}
              </span>
            </div>
          </div>

          {/* Body: sidebar + main + aside */}
          <div className={`${classPrefix}__body`}>
            {/* Sidebar */}
            <div className={`${classPrefix}__sidebar`}>
              {/* Around the Building */}
              <div
                className={`${classPrefix}__nav-item${navSel.area === 'around' ? ` ${classPrefix}__nav-item--active` : ''}`}
                onClick={() => handleNavSel('around')}
