// ─── handleUploadRequest ──────────────────────────────────────────────────────

const handleUploadRequest = async (option: RequestOptions) => {
  const { file, onProgress, onSuccess, onError } = option
  const formData = new FormData()
  formData.append('file', file)
  formData.append('type', String(File_UPLOAD_TYPE.INSPECTION_ANSWER))
  formData.append('uniqueId', String(Date.now()))
  try {
    const res: any = await patrolUploadFile(formData)
    onSuccess({ ...res })
  } catch (e) {
    onError(e)
  }
}

// ─── YesNoButtons ─────────────────────────────────────────────────────────────

interface YesNoButtonsProps {
  value?: Answer
  onChange?: (v: Answer) => void
}

const YesNoButtons = ({ value, onChange }: YesNoButtonsProps) => (
  <div className={`${classPrefix}__yes-no`}>
    {([1, 0] as const).map((opt) => (
      <button
        key={opt}
        type='button'
        className={`${classPrefix}__yes-no-btn ${
          value === opt
            ? `${classPrefix}__yes-no-btn--${opt === 1 ? 'yes' : 'no'}-active`
            : ''
        }`}
        onClick={() => onChange?.(opt)}
      >
        {opt === 1 ? 'Yes' : 'No'}
      </button>
    ))}
  </div>
)

// ─── AttachmentUpload ─────────────────────────────────────────────────────────

interface AttachmentUploadProps {
  value?: UploadItem[]
  onChange?: (v: UploadItem[]) => void
}

const AttachmentUpload = ({ value, onChange }: AttachmentUploadProps) => {
  const list = value ?? []

  const beforeUpload = (file: File) => {
    if (!['image/png', 'image/jpeg'].includes(file.type)) {
      Message.error('Only png and jpg files are supported')
      return false
    }
    if (file.size > ATTACHMENT_MAX_SIZE) {
      Message.error('File size must not exceed 20 MB')
      return false
    }
    return true
  }

  return (
    <Upload
      listType='picture-card'
      imagePreview
      fileList={list}
      accept='.png,.jpg'
      limit={ATTACHMENT_MAX}
      multiple
      beforeUpload={beforeUpload}
      customRequest={handleUploadRequest}
      onChange={(next) => onChange?.(next as UploadItem[])}
      showUploadList={{ startIcon: null }}
    >
      {list.length < ATTACHMENT_MAX ? (
        <div className={`${classPrefix}__upload-trigger`}>
          <IconPlus />
          <span>Upload</span>
        </div>
      ) : null}
    </Upload>
  )
}

