// ─── QuestionItem ─────────────────────────────────────────────────────────────
// 第二层
interface QuestionItemProps {
  form: ReturnType<typeof Form.useForm>[0]
  item: QuestionItem
  orgData: any
}

const QuestionItem = ({ form, item, orgData }: QuestionItemProps) => {
  const answer = Form.useWatch(`items.${item.id}.answer`, form) as Answer

  useEffect(() => {
    if (answer !== 0) return
    const path = `items.${item.id}.findings`
    const current = (form.getFieldValue(path) as Finding[] | undefined) ?? []
    if (current.length === 0) {
      form.setFieldValue(path, [
        { ...emptyFinding(), dept: item.defaultResponsibleOrgId ?? '' },
      ])
    }
  }, [answer])

  return (
    <div className={`${classPrefix}__item`}>
      <div className={`${classPrefix}__item-question`}>{item.question}</div>
      <Form.Item field={`items.${item.id}.answer`}>
        <YesNoButtons />
      </Form.Item>

      {answer === 0 && (
        <div className={`${classPrefix}__findings-wrap`}>
          <Form.List field={`items.${item.id}.findings`}>
            {(fields, { add, remove }) => (
              <>
                <div className={`${classPrefix}__findings-list`}>
                  {fields.map((field, idx) => (
                    <FindingCard
                      key={field.key}
                      fieldPrefix={field.field}
                      index={idx}
                      total={fields.length}
                      onRemove={() => remove(idx)}
                      orgData={orgData}
                    />
                  ))}
                </div>
                <div className={`${classPrefix}__finding-divider`} />
                <Button
                  icon={<IconPlus />}
                  onClick={() => add(emptyFinding())}
                  className={`${classPrefix}__add-finding-btn`}
                >
                  Add Finding
                </Button>
              </>
            )}
          </Form.List>
        </div>
      )}
    </div>
  )
}

