const AttachmentUpload = ({ value, onChange }: AttachmentUploadProps) => {
  const list = value ?? []

  const beforeUpload = (file: File) => {
    if (!['image/png', 'image/jpeg'].includes(file.type)) {
      Message.error('Only png and jpg files are supported')
      return false
    }
    if (file.size > ATTACHMENT_MAX_SIZE) {
      Message.error('File size must not exceed 20 MB')
      return false
    }
    return true
  }

  return (
    <Upload
      listType='picture-card'
      imagePreview
      fileList={list}
      accept='.png,.jpg'
      limit={ATTACHMENT_MAX}
      multiple
      beforeUpload={beforeUpload}
      customRequest={handleUploadRequest}
      onChange={(next) => onChange?.(next as UploadItem[])}
      showUploadList={{ startIcon: null }}
    >
      {list.length < ATTACHMENT_MAX ? (
        <div className={`${classPrefix}__upload-trigger`}>
          <IconPlus />
          <span>Upload</span>
        </div>
      ) : null}
    </Upload>
  )
}

