import './index.less'
import { useCallback, useMemo, useRef, useState } from 'react'
import {
  Badge,
  Button,
  DatePicker,
  Form,
  Input,
  Link,
  Modal,
  Radio,
  Select,
  Space,
  Divider,
} from '@arco-design/web-react'
import type { TableColumnProps } from '@arco-design/web-react'
import {
  IconClose,
  IconEye,
  IconPen,
  IconPlus,
  IconUpload,
  IconDelete,
  IconSearch,
} from '@arco-design/web-react/icon'
import { useTranslation } from 'react-i18next'
import ContractorHeader from '../components/ContractorHeader'
import ListFilterHseForm from '@common/components/ListFilterHseForm'
import UnifiedTableStyle from '@common/components/UnifiedTableStyle'
import { renderEllipsisText } from '@common/components/EllipsisText'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import { tableHeaderCellStyle } from '@/constants/table'
import { useNavigate } from 'react-router-dom'
import { getPatrolList, savePatrol, deletePatrol } from '@/service'
import DeleteConfirmModal from '@common/components/DeleteConfirmModal'
import { useRequest } from 'ahooks'
import { ContractorApproval } from '@/constants/contractor'


// status: 0=Draft 1=UnderReview 2=Approved 3=Rejected
// shift:  1=Day   2=Night

interface PatrolRecordRow {
  patrolId: number
  patrolDate: string
  shift: number
  patrollerUserId: number
  patrollerUser: string
  status: number
  answerCount: number
  issuesObserved: number
  inspector: string
  reportTime: string
  patroller: any
}

interface PatrolRecordFilters {
  status?: number
  patrolDate?: { startTime?: string; endTime?: string }
  shift?: any
  patroller?: any
}

const classPrefix = 'contractor-patrol-record'

const statusColorMap: Record<number, string> = {
  0: '#86909C',
  1: '#FF7D00',
  2: '#45AD5E',
  3: '#F53F3F',
}

interface AddPatrolFormValues {
  shift: number
  patrollerName: string
  patrolDate?: string
}

const today = new Date().toISOString().slice(0, 10)

const PatrolRecord = () => {
  const { t } = useTranslation(['contractorPatrolRecord', 'securityPatrol', 'common'])
  const navigate = useNavigate()
  const tableRef = useRef<any>(null)
  const [filters, setFilters] = useState<PatrolRecordFilters>({})
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const [addModalVisible, setAddModalVisible] = useState(false)
  const [deleteModalVisible, setDeleteModalVisible] = useState(false)
  const [pendingDeleteId, setPendingDeleteId] = useState<number | null>(null)
  const [addForm] = Form.useForm<AddPatrolFormValues>()
  const formDataRef = useRef<AddPatrolFormValues | null>(null)

  const statusOptions = useMemo(
    () => [
      { label: t('securityPatrol:status.draft'), value: 0 },
      { label: t('securityPatrol:status.underReview'), value: 1 },
      { label: t('securityPatrol:status.approved'), value: 2 },
      { label: t('securityPatrol:status.rejected'), value: 3 },
    ],
    [t],
  )

  const getList = useCallback(
    async (params?: { pageNum?: number; pageSize?: number }) => {
      const pageNum = params?.pageNum || 1
      const pageSize = params?.pageSize || 20

      const res: any = await getPatrolList({
        pageNum,
        pageSize,
        keyword: filters.patroller ?? undefined,
        status: filters.status ?? undefined,
        startDate: filters.patrolDate?.startTime || undefined,
        endDate: filters.patrolDate?.endTime || undefined,
      })

      const list: PatrolRecordRow[] = res?.list || []
      const total: number = res?.total || 0

      return { list, total, pageNum, pageSize }
    },
    [filters],
  )

  const handleSubmit = (values: PatrolRecordFilters) => {
    setFilters(values || {})
    tableRef.current?.setPageNum?.(1)
    tableRef.current?.refresh?.()
  }

  const handleReset = () => {
    setFilters({})
    tableRef.current?.setPageNum?.(1)
    tableRef.current?.refresh?.()
  }

  const columns: TableColumnProps<PatrolRecordRow>[] = useMemo(
    () => [
      {
        title: t('securityPatrol:patrolRecords.columns.patrolId'),
        dataIndex: 'code',
        width: 160,
        headerCellStyle: tableHeaderCellStyle,
      },
      {
        title: t('securityPatrol:patrolRecords.columns.patrolDate'),
        dataIndex: 'patrolDate',
        width: 160,
        headerCellStyle: tableHeaderCellStyle,
      },
      {
        title: t('securityPatrol:patrolRecords.columns.shift'),
        dataIndex: 'shift',
        width: 120,
        headerCellStyle: tableHeaderCellStyle,
        render: (value: number) =>
          value === 1
            ? t('securityPatrol:shift.day')
            : value === 2
              ? t('securityPatrol:shift.night')
              : value,
      },
      {
        title: t('securityPatrol:patrolRecords.columns.patroller'),
        dataIndex: 'inspector',
        width: 120,
        headerCellStyle: tableHeaderCellStyle,
        render: (_, record) => {
          return renderEllipsisText(record?.inspector)
        },
      },
      {
        title: t('securityPatrol:patrolRecords.columns.issues'),
        dataIndex: 'issuesObserved',
        width: 100,
        headerCellStyle: tableHeaderCellStyle,
      },
      {
        title: t('securityPatrol:patrolRecords.columns.status'),
        dataIndex: 'status',
        width: 110,
        headerCellStyle: tableHeaderCellStyle,
        render: (value: number) => (
          <Badge
            color={statusColorMap[value] ?? '#86909C'}
            text={t(`securityPatrol:status.${['draft','underReview','approved','rejected'][value] ?? 'draft'}`)}
          />
        ),
      },
      {
        title: t('contractorPatrolRecord:columns.lastUpdated'),
        dataIndex: 'lastUpdatedTime',
        width: 150,
        headerCellStyle: tableHeaderCellStyle,
        render: (_, record) => {
          return renderEllipsisText(record?.reportTime)
        },
      },
      {
        title: t('securityPatrol:patrolRecords.columns.action'),
        dataIndex: 'actions',
        width: 80,
        fixed: 'right',
        headerCellStyle: tableHeaderCellStyle,
        render: (_value, record) => {
          // const isEditable = record.status === 0 || record.status === 3
          const isEditable = record.status
          return (
            <div className='patrol-record-actions'>
              {
                <Link
                  icon={
                    isEditable == ContractorApproval.Open ? (
                      <IconPen />
                    ) : (
                      <IconEye />
                    )
                  }
                  className='coc-table-link'
                  onClick={() =>
                    isEditable == ContractorApproval.Open
                      ? navigate(`/contractor/addOrEdit/${record?.patrolId}`)
                      : isEditable != ContractorApproval.Open
                        ? navigate(`/contractor/detail/${record?.patrolId}`, {
                            state: {
                              status: record?.status,
                            },
                          })
                        : null
                  }
                ></Link>
              }
              <Divider type='vertical' className='actions-divider' />

              <Link
                icon={<IconDelete />}
                className='coc-table-link'
                onClick={() => handleDelete(record?.patrolId)}
                disabled={record.status != ContractorApproval.Open}
              ></Link>
            </div>
          )
        },
      },
    ],
    [isLanguageAR, navigate, t],
  )

  const { loading: deleteLoading, run: runDelete } = useRequest(deletePatrol, {
    manual: true,
    onSuccess: () => {
      setDeleteModalVisible(false)
      setPendingDeleteId(null)
      tableRef.current?.refresh?.()
    },
    onError: () => {
      setDeleteModalVisible(false)
      setPendingDeleteId(null)
    },
  })

  const handleDelete = (patrolId: number) => {
    setPendingDeleteId(patrolId)
    setDeleteModalVisible(true)
  }

  const handleDeleteConfirm = () => {
    if (pendingDeleteId !== null) {
      runDelete({ patrolId: pendingDeleteId })
    }
  }

  const handleDeleteCancel = () => {
    setDeleteModalVisible(false)
    setPendingDeleteId(null)
  }

  const { run: runPatrolId, loading: getPatrolIdLoading } = useRequest(
    savePatrol,
    {
      manual: true,
      onSuccess: (res: any) => {
        navigate(`/contractor/addOrEdit/${res}`, { state: formDataRef.current })
        setAddModalVisible(false)
        addForm.resetFields()
      },
    },
  )

  const addPatrol = () => {
    setAddModalVisible(true)
  }

  const handleAddConfirm = () => {
    addForm.validate().then((values) => {
      formDataRef.current = { ...values, patrolDate: today }
      const data = formDataRef.current
      runPatrolId(data)
    })
  }

  const handleAddCancel = () => {
    setAddModalVisible(false)
    addForm.resetFields()
  }
  return (
    <div className={classPrefix}>
      <ContractorHeader />
      <div className={`${classPrefix}__content`}>
        <ListFilterHseForm
          showKeywordInput={false}
          onSubmit={handleSubmit}
          onReset={handleReset}
          renderBtnJsx={
            <Button type='primary' icon={<IconPlus />} onClick={addPatrol}>
              {t('contractorPatrolRecord:addButton')}
            </Button>
          }
        >
          <div className='search-form-box'>
            <Form.Item field='patroller'>
              <Input
                allowClear
                prefix={<IconSearch />}
                placeholder={t('securityPatrol:filters.searchPatroller')}
                style={{ width: 220 }}
              />
            </Form.Item>
            <Form.Item field='status'>
              <Select
                allowClear
                placeholder={t('securityPatrol:filters.status')}
                options={statusOptions}
                style={{ width: 180 }}
              />
            </Form.Item>
            <Form.Item
              field='patrolDate'
              normalize={(value) => ({
                startTime: value?.[0],
                endTime: value?.[1],
              })}
              formatter={(value) =>
                value?.startTime ? [value.startTime, value.endTime] : []
              }
            >
              <DatePicker.RangePicker
                format='YYYY-MM-DD'
                placeholder={[t('securityPatrol:filters.dateFrom'), t('securityPatrol:filters.dateTo')]}
                style={{ width: 260 }}
              />
            </Form.Item>
          </div>
        </ListFilterHseForm>
        <div className={`${classPrefix}__table`}>
          <UnifiedTableStyle
            ref={tableRef}
            rowKey='securityPatrolId'
            columns={columns}
            getList={getList}
            showNoColumn={false}
            showPagination={true}
            border={true}
            tableHeight={40}
          />
        </div>
      </div>

      <DeleteConfirmModal
        visible={deleteModalVisible}
        loading={deleteLoading}
        onOk={handleDeleteConfirm}
        onCancel={handleDeleteCancel}
      />

      <Modal
        title={t('contractorPatrolRecord:modal.addTitle')}
        visible={addModalVisible}
        onCancel={handleAddCancel}
        footer={
          <Space>
            <Button icon={<IconClose />} onClick={handleAddCancel}>
              {t('common:btn.cancel')}
            </Button>
            <Button
              type='primary'
              icon={<IconUpload />}
              loading={getPatrolIdLoading}
              onClick={handleAddConfirm}
            >
              {t('common:btn.confirm')}
            </Button>
          </Space>
        }
      >
        <Form form={addForm} layout='vertical' initialValues={{ shift: 1 }}>
          <Form.Item label={t('securityPatrol:patrolRecords.columns.patrolDate')}>
            <Input value={today} disabled />
          </Form.Item>
          <Form.Item
            field='shift'
            label={t('securityPatrol:patrolRecords.columns.shift')}
            rules={[{ required: true, message: t('contractorPatrolRecord:validation.pleaseSelectShift') }]}
          >
            <Radio.Group>
              <Radio value={1}>{t('securityPatrol:shift.day')}</Radio>
              <Radio value={2}>{t('securityPatrol:shift.night')}</Radio>
            </Radio.Group>
          </Form.Item>
          <Form.Item
            field='inspector'
            label={t('securityPatrol:patrolRecords.detail.patrollerName')}
            rules={[{ required: true, message: t('contractorPatrolRecord:validation.pleaseEnterPatrollerName') }]}
          >
            <Input placeholder={t('contractorPatrolRecord:placeholder.enterPatrollerName')} />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  )
}

export default PatrolRecord

