import './index.less'
import { useEffect, useMemo, useRef, useState } from 'react'
import {
  Button,
  DatePicker,
  Form,
  Input,
  Message,
  Spin,
  Upload,
  Modal,
  TreeSelect,
  Tooltip,
} from '@arco-design/web-react'
import {
  IconClose,
  IconDelete,
  IconDown,
  IconInfoCircleFill,
  IconPlus,
  IconSave,
  IconUp,
  IconUpload,
} from '@arco-design/web-react/icon'
import type { UploadItem } from '@arco-design/web-react/es/Upload/interface'
import type { RequestOptions } from '@arco-design/web-react/es/Upload/interface'
import ContractorHeader from '../../../components/ContractorHeader'
import { uploadFile } from '@common/service/apis/file'
import { File_UPLOAD_TYPE } from '@common/constants/uploadTypes'
import { useNavigate, useParams } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { useRequest } from 'ahooks'
import {
  getPatrolDetail,
  patrolFindingCount,
  savePatrolForm,
  getPatrolOrgTreeRecursion,
  patrolUploadFile,
  submitPatrolForm,
} from '@/service'
import { handelFieldNameShow, orgTransformData } from '@/utils/tools'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import { contractorAuthStorage } from '@/pages/Contractor/contractorAuth'
import { ContractorApproval } from '@/constants/contractor'

// ─── Types ────────────────────────────────────────────────────────────────────

type Answer = 1 | 0 | null

interface Finding {
  findingId?: string | null
  notesAr: string
  notesEn: string
  attachments: UploadItem[]
  correctiveActionAr: string
  correctiveActionEn: string
  dept: string
  targetClosureDate: string
}

interface QuestionItem {
  id: string
  question: string
  defaultResponsibleOrgId?: string
}

interface Section {
  id: string
  no: number
  title: string
  defaultOpen: boolean
  items: QuestionItem[]
}

type ItemState = Record<
  string,
  { answer: Answer; findings: Finding[] } | undefined
>

const INSIDE_FLOORS = [
  { label: 'G', value: 0 },
  { label: 'M', value: 1 },
  { label: '1', value: 2 },
  { label: '2', value: 3 },
  { label: '3', value: 4 },
  { label: '4', value: 5 },
  { label: '5', value: 6 },
  { label: '6', value: 7 },
  { label: 'RF', value: 8 },
] as const
type FloorKey = (typeof INSIDE_FLOORS)[number]

const PARKING_SUBS = [
  { label: 'P1', value: 9 },
  { label: 'P2', value: 10 },
  { label: 'P3', value: 11 },
] as const
type ParkingKey = (typeof PARKING_SUBS)[number]

type NavSel =
  | { area: 'around' }
  | { area: 'inside'; floor: FloorKey }
  | { area: 'parking'; sub: ParkingKey }

// ─── Helpers ──────────────────────────────────────────────────────────────────

const filterEmptyOrgNodes = (nodes: any[]): any[] =>
  (nodes ?? [])
    .filter((node) => node.title)
    .map((node) =>
      node.children?.length
        ? { ...node, children: filterEmptyOrgNodes(node.children) }
        : node,
    )

// ─── Constants ────────────────────────────────────────────────────────────────

const classPrefix = 'patrol-add-edit'
const NOTES_MAX = 500
const ATTACHMENT_MAX = 3
const ATTACHMENT_MAX_SIZE = 20 * 1024 * 1024

const emptyFinding = (): Finding => ({
  findingId: null,
  notesAr: '',
  notesEn: '',
  attachments: [],
  correctiveActionAr: '',
  correctiveActionEn: '',
  dept: '',
  targetClosureDate: '',
})

// ─── Helper functions ─────────────────────────────────────────────────────────

// ─── handleUploadRequest ──────────────────────────────────────────────────────

const handleUploadRequest = async (option: RequestOptions) => {
  const { file, onProgress, onSuccess, onError } = option
  const formData = new FormData()
  formData.append('file', file)
  formData.append('type', String(File_UPLOAD_TYPE.INSPECTION_ANSWER))
  formData.append('uniqueId', String(Date.now()))
  try {
    const res: any = await patrolUploadFile(formData)
    onSuccess({ ...res })
  } catch (e) {
    onError(e)
  }
}

// ─── YesNoButtons ─────────────────────────────────────────────────────────────

interface YesNoButtonsProps {
  value?: Answer
  onChange?: (v: Answer) => void
}

const YesNoButtons = ({ value, onChange }: YesNoButtonsProps) => {
  const { t } = useTranslation(['common'])
  return (
    <div className={`${classPrefix}__yes-no`}>
      {([1, 0] as const).map((opt) => (
        <button
          key={opt}
          type='button'
          className={`${classPrefix}__yes-no-btn ${
            value === opt
              ? `${classPrefix}__yes-no-btn--${opt === 1 ? 'yes' : 'no'}-active`
              : ''
          }`}
          onClick={() => onChange?.(opt)}
        >
          {opt === 1 ? t('common:yes') : t('common:no')}
        </button>
      ))}
    </div>
  )
}

// ─── AttachmentUpload ─────────────────────────────────────────────────────────

interface AttachmentUploadProps {
  value?: UploadItem[]
  onChange?: (v: UploadItem[]) => void
}

const AttachmentUpload = ({ value, onChange }: AttachmentUploadProps) => {
  const { t } = useTranslation(['contractorPatrolRecord', 'common'])
  const list = value ?? []

  const beforeUpload = (file: File) => {
    if (!['image/png', 'image/jpeg'].includes(file.type)) {
      Message.error(t('contractorPatrolRecord:upload.onlyPngJpg'))
      return false
    }
    if (file.size > ATTACHMENT_MAX_SIZE) {
      Message.error(t('contractorPatrolRecord:upload.fileSizeLimit'))
      return false
    }
    return true
  }

  return (
    <Upload
      listType='picture-card'
      imagePreview
      fileList={list}
      accept='.png,.jpg'
      limit={ATTACHMENT_MAX}
      multiple
      beforeUpload={beforeUpload}
      customRequest={handleUploadRequest}
      onChange={(next) => onChange?.(next as UploadItem[])}
      showUploadList={{ startIcon: null }}
    >
      {list.length < ATTACHMENT_MAX ? (
        <div className={`${classPrefix}__upload-trigger`}>
          <IconPlus />
          <span>{t('common:upload')}</span>
        </div>
      ) : null}
    </Upload>
  )
}

// ─── FindingCard ──────────────────────────────────────────────────────────────
// 第三层
interface FindingCardProps {
  fieldPrefix: string
  index: number
  total: number
  onRemove: () => void
  orgData: any
}

const FindingCard = ({
  fieldPrefix,
  index,
  total,
  onRemove,
  orgData,
}: FindingCardProps) => {
  const { t } = useTranslation(['contractorPatrolRecord', 'incidentReport', 'common'])
  return (
  <div
    className={`${classPrefix}__finding${index > 0 ? ` ${classPrefix}__finding--mt` : ''}`}
  >
    <div className={`${classPrefix}__finding-head`}>
      <span className={`${classPrefix}__finding-title`}>
        {t('contractorPatrolRecord:finding', { n: index + 1 })}
      </span>
      <Button
        type='text'
        size='mini'
        icon={<IconDelete />}
        status={total > 1 ? 'danger' : 'default'}
        style={total <= 1 ? { color: '#C9CDD4' } : undefined}
        onClick={total > 1 ? onRemove : undefined}
      />
    </div>

    <div className={`${classPrefix}__finding-body`}>
      <div className={`${classPrefix}__field-block`}>
        {/* <div
          className={`${classPrefix}__field-label ${classPrefix}__field-label--required`}
        >
          Notes/Remarks (Ar)
        </div> */}
        <Form.Item
          label={'Notes/Remarks (Ar)'}
          field={`${fieldPrefix}.notesAr`}
          rules={[{ required: true, message: 'Please enter' }]}
        >
          <Input.TextArea
            placeholder='Please enter...'
            maxLength={NOTES_MAX}
            showWordLimit
            autoSize={{ minRows: 2 }}
          />
        </Form.Item>
      </div>

      <div className={`${classPrefix}__field-block`}>
        {/* <div className={`${classPrefix}__field-label`}>Notes/Remarks (En)</div> */}
        <Form.Item
          label={'Notes/Remarks (En)'}
          field={`${fieldPrefix}.notesEn`}
        >
          <Input.TextArea
            placeholder='Please enter...'
            maxLength={NOTES_MAX}
            showWordLimit
            autoSize={{ minRows: 2 }}
          />
        </Form.Item>
      </div>

      <div className={`${classPrefix}__field-block`}>
        {/* <div
          className={`${classPrefix}__field-label ${classPrefix}__field-label--required`}
        >
          Attachment
        </div> */}
        <div className={`${classPrefix}__upload-tip`}>
          Support format: png, jpg; Max 3 files, size 20 MB each
        </div>
        <Form.Item
          label={'Attachment'}
          field={`${fieldPrefix}.attachments`}
          rules={[{ required: true, message: 'Please enter' }]}
        >
          <AttachmentUpload />
        </Form.Item>
      </div>

      <div className={`${classPrefix}__field-block`}>
        {/* <div
          className={`${classPrefix}__field-label ${classPrefix}__field-label--required`}
        >
          Corrective Actions (Ar)
        </div> */}
        <Form.Item
          label={'Corrective Actions (Ar)'}
          field={`${fieldPrefix}.correctiveActionAr`}
          rules={[{ required: true, message: 'Please enter' }]}
        >
          <Input.TextArea
            placeholder='Please enter...'
            maxLength={NOTES_MAX}
            showWordLimit
            autoSize={{ minRows: 2 }}
          />
        </Form.Item>
      </div>

      <div className={`${classPrefix}__field-block`}>
        {/* <div className={`${classPrefix}__field-label`}>
          Corrective Actions (En)
        </div> */}
        <Form.Item
          field={`${fieldPrefix}.correctiveActionEn`}
          label={'Corrective Actions (En)'}
        >
          <Input.TextArea
            placeholder='Please enter...'
            maxLength={NOTES_MAX}
            showWordLimit
            autoSize={{ minRows: 2 }}
          />
        </Form.Item>
      </div>

      <div className={`${classPrefix}__finding-row`}>
        <Form.Item
          label={'Responsible Department'}
          field={`${fieldPrefix}.dept`}
          rules={[{ required: true, message: 'Please select' }]}
        >
          {/* <Select
            placeholder='Please select'
            options={DEPT_OPTIONS}
            allowClear
          /> */}
          <TreeSelect
            className={`${classPrefix}__item-dept-select`}
            treeData={orgData}
            // placeholder={t('common:pleaseSelect')}
            allowClear
            showSearch
            filterTreeNode={(inputValue, node) =>
              (node.title as string)
                ?.toLowerCase()
                .includes(inputValue.toLowerCase())
            }
          />
        </Form.Item>
        <Form.Item
          label={'Target Closure Date'}
          field={`${fieldPrefix}.targetClosureDate`}
          rules={[{ required: true, message: 'Please select date' }]}
        >
          <DatePicker
            placeholder='Please select date'
            style={{ width: '100%' }}
            format='DD/MM/YYYY'
          />
        </Form.Item>
      </div>
    </div>
  </div>
)

// ─── QuestionItem ─────────────────────────────────────────────────────────────
// 第二层
interface QuestionItemProps {
  form: ReturnType<typeof Form.useForm>[0]
  item: QuestionItem
  orgData: any
}

const QuestionItem = ({ form, item, orgData }: QuestionItemProps) => {
  const answer = Form.useWatch(`items.${item.id}.answer`, form) as Answer

  useEffect(() => {
    if (answer !== 0) return
    const path = `items.${item.id}.findings`
    const current = (form.getFieldValue(path) as Finding[] | undefined) ?? []
    if (current.length === 0) {
      form.setFieldValue(path, [
        { ...emptyFinding(), dept: item.defaultResponsibleOrgId ?? '' },
      ])
    }
  }, [answer])

  return (
    <div className={`${classPrefix}__item`}>
      <div className={`${classPrefix}__item-question`}>{item.question}</div>
      <Form.Item field={`items.${item.id}.answer`}>
        <YesNoButtons />
      </Form.Item>

      {answer === 0 && (
        <div className={`${classPrefix}__findings-wrap`}>
          <Form.List field={`items.${item.id}.findings`}>
            {(fields, { add, remove }) => (
              <>
                <div className={`${classPrefix}__findings-list`}>
                  {fields.map((field, idx) => (
                    <FindingCard
                      key={field.key}
                      fieldPrefix={field.field}
                      index={idx}
                      total={fields.length}
                      onRemove={() => remove(idx)}
                      orgData={orgData}
                    />
                  ))}
                </div>
                <div className={`${classPrefix}__finding-divider`} />
                <Button
                  icon={<IconPlus />}
                  onClick={() => add(emptyFinding())}
                  className={`${classPrefix}__add-finding-btn`}
                >
                  Add Finding
                </Button>
              </>
            )}
          </Form.List>
        </div>
      )}
    </div>
  )
}

// ─── SectionCard ──────────────────────────────────────────────────────────────
// 第一层
interface SectionCardProps {
  form: ReturnType<typeof Form.useForm>[0]
  section: Section
  orgData: any
}

const SectionCard = ({ form, section, orgData }: SectionCardProps) => {
  const [open, setOpen] = useState(section.defaultOpen)

  return (
    <div className={`${classPrefix}__section`}>
      <div
        className={`${classPrefix}__section-header${open ? ` ${classPrefix}__section-header--open` : ''}`}
        onClick={() => setOpen((v) => !v)}
      >
        <div>
          <div className={`${classPrefix}__section-no`}>
            CATEGORY {section.no}
          </div>
          <div className={`${classPrefix}__section-title`}>{section.title}</div>
        </div>
        {open ? <IconUp /> : <IconDown />}
      </div>
      {open && (
        <div className={`${classPrefix}__section-body`}>
          {section.items.map((item) => (
            <QuestionItem
              key={item.id}
              form={form}
              item={item}
              orgData={orgData}
            />
          ))}
        </div>
      )}
    </div>
  )
}

// ─── Main component ───────────────────────────────────────────────────────────

const PatrolRecordAddOrEdit = () => {
  useTranslation(['incidentReport', 'common'])
  const { id } = useParams()
  const navigate = useNavigate()
  const [form] = Form.useForm()
  const lastSavedItemsRef = useRef<ItemState>({})

  const [navSel, setNavSel] = useState<NavSel>({ area: 'around' })
  const [submitModalVisible, setSubmitModalVisible] = useState(false)
  const [inspectorName, setInspectorName] = useState('')

  const [orgData, setOrgData] = useState<any[]>([])

  const [findingCount, setFindingCount] = useState<any>()
  const [detailData, setDetailData] = useState<any>(null)
  const isLanguageAR = getLanguage() === LanguageEnum.AR

  const contentTitle =
    navSel.area === 'around'
      ? 'Around the Building'
      : navSel.area === 'inside'
        ? `Inside the Building - Floor ${navSel.floor.label}`
        : `Parking - ${navSel.sub.label}`

  const { run: runPatrolFindingCount, loading: patrolFindingCountLoading } =
    useRequest(patrolFindingCount, {
      manual: true,
      onSuccess: (res: any) => {
        setFindingCount(res)
      },
    })

  useEffect(() => {
    if (id) {
      runPatrolFindingCount({ patrolId: id })
      runPatrolDetail({ patrolId: id, type: 1, floor: -1 })
      fetchOrgTree()
    }
  }, [id])

  //form 表单
  const { run: runPatrolFormSave, loading: patrolFormSaveLoading } = useRequest(
    savePatrolForm,
    {
      manual: true,
      onSuccess: () => {
        Message.success('Saved successfully')
        if (id) runPatrolFindingCount({ patrolId: id })
        lastSavedItemsRef.current =
          (form.getFieldsValue().items as ItemState) || {}
      },
    },
  )
  const { run: runSubmitPatrolForm, loading: submitPatrolFormLoading } =
    useRequest(submitPatrolForm, {
      manual: true,
      onSuccess: (res: any) => {
        navigate('/contractor/list')
      },
    })

  const handleSubmit = () => {
    if (!isAllSaved) {
      Message.warning(
        'Please complete and save all sections (Around, Inside floors, Parking) before submitting.',
      )
      return
    }
    form.validate().then(() => {
      setInspectorName('')
      setSubmitModalVisible(true)
    })
  }

  const handleConfirmSubmit = () => {
    setSubmitModalVisible(false)
    runSubmitPatrolForm({ patrolId: id })
    // navigate('/contractor/list')
  }

  const { run: runPatrolDetail, loading: patrolDetailLoading } = useRequest(getPatrolDetail, {
    manual: true,
    onSuccess: (res: any) => {
      setDetailData(res)
      const answerList: any[] = res?.patrolAnswerList ?? []
      const newItems: ItemState = {}
      answerList.forEach((ans: any) => {
        const answer: Answer = ans?.isSituation == 0 ? 0 : 1
        const findings: Finding[] =
          ans.isSituation === 0 && ans.findings?.length
            ? ans.findings.map(
                (f: any): Finding => ({
                  findingId: f.correctiveActionId ?? null,
                  notesAr: f.findingRemarkAr ?? '',
                  notesEn: f.findingRemark ?? '',
                  attachments: (f.attachmentList ?? []).map(
                    (att: any): UploadItem => ({
                      uid: att.attachmentId ?? att.id,
                      name: att.fileName ?? '',
                      url: att.absUrl ?? att.url,
                      status: 'done',
                      response: att,
                    }),
                  ),
                  correctiveActionAr: f.correctiveActionAr ?? '',
                  correctiveActionEn: f.correctiveAction ?? '',
                  dept: f.orgId ?? '',
                  targetClosureDate: f.targetClosureDate ?? '',
                }),
              )
            : ans.isSituation === 0
              ? [{ ...emptyFinding(), dept: ans.defaultResponsibleOrgId ?? '' }]
              : []
        newItems[String(ans.itemId)] = { answer, findings }
      })
      form.setFieldsValue({ items: newItems })
      lastSavedItemsRef.current = newItems
    },
  })

  const doNavSel = (area, value: any) => {
    let type = null
    let floor = null
    if (area == 'around') {
      setNavSel({ area })
      type = 1
      floor = -1
    } else if (area == 'inside') {
      setNavSel({ area, floor: value })
      type = 2
      floor = value?.value
    } else if (area == 'parking') {
      setNavSel({ area, sub: value })
      type = 3
      floor = value?.value
    }
    runPatrolDetail({ patrolId: id, type, floor })
  }

  const handleNavSel = (area, value: any) => {
    const currentItems =
      (form.getFieldsValue().items as ItemState | undefined) || {}
    const hasUnsavedNo = Object.entries(currentItems).some(([itemId, state]) => {
      if (state?.answer !== 0) return false
      return lastSavedItemsRef.current[itemId]?.answer !== 0
    })

    if (hasUnsavedNo) {
      Modal.confirm({
        title: 'Unsaved Changes',
        content:
          'Some items have "No" selected but have not been saved. Please click "Check & Save" before switching sections.',
        okText: 'Stay & Save',
        cancelText: 'Switch Anyway',
        onOk: () => {},
        onCancel: () => doNavSel(area, value),
      })
      return
    }

    doNavSel(area, value)
  }

  const dynamicSections = useMemo((): Section[] => {
    const answerList: any[] = detailData?.patrolAnswerList ?? []
    if (!answerList.length) return []
    const map = new Map<string, Section>()
    answerList.forEach((ans: any) => {
      const key = String(ans.sectionId)
      if (!map.has(key)) {
        map.set(key, {
          id: `sec-${key}`,
          no: map.size + 1,
          title: isLanguageAR
            ? ans.sectionNameAr || ans.sectionName
            : ans.sectionName,
          defaultOpen: map.size === 0,
          items: [],
        })
      }
      map.get(key)!.items.push({
        id: String(ans.itemId),
        question: isLanguageAR ? ans.itemNameAr || ans.itemName : ans.itemName,
        defaultResponsibleOrgId: ans.defaultResponsibleOrgId,
      })
    })
    return Array.from(map.values())
  }, [detailData, isLanguageAR])

  const handleCheckSave = () => {
    form.validate().then(() => {
    const values = form.getFieldsValue()
    const items = values.items as ItemState | undefined
    let type = 1
    let floor: number = -1
    if (navSel.area === 'inside') {
      type = 2
      floor = navSel.floor.value
    } else if (navSel.area === 'parking') {
      type = 3
      floor = navSel.sub.value
    }
    const answerList: any[] = detailData?.patrolAnswerList ?? []
    const patrolAnswerList = answerList.map((ans: any) => {
      const formItem = items?.[String(ans.itemId)]
      const isSituation = formItem?.answer == 0 ? 0 : 1
      const findings =
        formItem?.answer === 0
          ? (formItem.findings ?? []).map((f: Finding) => ({
              ...(f.findingId ? { correctiveActionId: f.findingId } : {}),
              correctiveActionAr: f.correctiveActionAr,
              correctiveAction: f.correctiveActionEn,
              findingRemarkAr: f.notesAr,
              findingRemark: f.notesEn,
              orgId: f.dept,
              targetClosureDate: f?.targetClosureDate,
              attachmentList: (f?.attachments ?? []).map((a: any) => {
                return {
                  attachmentId: a?.response?.attachmentId,
                  id: a?.response?.id,
                  uniqueId: a?.response?.uniqueId,
                  fileName: a?.response?.fileName,
                  fileType: a?.response?.fileType,
                  absUrl: a?.response?.absUrl,
                  url: a?.response?.url,
                }
              }),
            }))
          : []
      return {
        patrolAnswerId: ans.patrolAnswerId,
        itemId: ans.itemId,
        isSituation,
        findings,
      }
    })
    runPatrolFormSave({
      patrolId: id,
      type,
      floorCode: floor,
      patrolAnswerSaveList: patrolAnswerList,
    })
    })
  }

  const aroundApiData = (findingCount as any[] | undefined)?.find(
    (x: any) => x.type === 1,
  )
  const insideApiData = (findingCount as any[] | undefined)?.find(
    (x: any) => x.type === 2,
  )
  const parkingApiData = (findingCount as any[] | undefined)?.find(
    (x: any) => x.type === 3,
  )

  const getInsideFloorData = (floor: FloorKey) =>
    insideApiData?.floorSummaryList?.find(
      (f: any) => f.floorCode === floor.value,
    )

  const getParkingSubData = (sub: ParkingKey) =>
    parkingApiData?.floorSummaryList?.find(
      (f: any) => f.floorCode === sub.value,
    )

  const isAllSaved = useMemo(() => {
    if (!findingCount) return false
    if (aroundApiData?.floorSummaryList?.[0]?.saveStatus !== 1) return false
    for (const floor of INSIDE_FLOORS) {
      const floorData = insideApiData?.floorSummaryList?.find(
        (f: any) => f.floorCode === floor.value,
      )
      if (floorData?.saveStatus !== 1) return false
    }
    for (const sub of PARKING_SUBS) {
      const subData = parkingApiData?.floorSummaryList?.find(
        (f: any) => f.floorCode === sub.value,
      )
      if (subData?.saveStatus !== 1) return false
    }
    return true
  }, [findingCount, aroundApiData, insideApiData, parkingApiData])

  const { run: fetchOrgTree } = useRequest(getPatrolOrgTreeRecursion, {
    manual: true,
    onSuccess: (res: any) => {
      setOrgData(filterEmptyOrgNodes(orgTransformData(res || [])))
    },
  })

  return (
    <div className={classPrefix}>
      <ContractorHeader />

      <div className={`${classPrefix}__wrapper`}>
        <div className={`${classPrefix}__card`}>
          {/* Card header */}
          <div className={`${classPrefix}__card-header`}>
            <span className={`${classPrefix}__card-title`}>
              Security Patrol Detail
            </span>
            <div className={`${classPrefix}__status-badge`}>
              <span className={`${classPrefix}__status-badge-dot`} />
              <span className={`${classPrefix}__status-badge-text`}>Draft</span>
            </div>
          </div>

          {/* Meta bar */}
          <div className={`${classPrefix}__meta-bar`}>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>Patrol ID</span>
              <span className={`${classPrefix}__meta-value`}>
                {detailData?.code ?? '--'}
              </span>
            </div>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>Patrol Date</span>
              <span className={`${classPrefix}__meta-value`}>
                {detailData?.patrolDate ?? '--'}
              </span>
            </div>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>Shift</span>
              <span className={`${classPrefix}__meta-value`}>
                {detailData?.shift === 1
                  ? 'Day'
                  : detailData?.shift === 2
                    ? 'Night'
                    : '--'}
              </span>
            </div>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>Contractor</span>
              <span className={`${classPrefix}__meta-value`}>
                {detailData?.reportedByName}
              </span>
            </div>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>
                Patroller Name
              </span>
              <span className={`${classPrefix}__meta-value`}>
                {detailData?.inspector || '--'}
              </span>
            </div>
          </div>

          {/* Main: sidebar + content */}
          <div className={`${classPrefix}__main`}>
            {/* Sidebar */}
            <div className={`${classPrefix}__sidebar`}>
              {/* Around the Building tab 一一一 */}
              <div
                className={`${classPrefix}__nav-item${navSel.area === 'around' ? ` ${classPrefix}__nav-item--active` : ''}`}
                onClick={() => handleNavSel('around', null)}
              >
                {aroundApiData?.floorSummaryList?.[0]?.saveStatus === 1 ? (
                  <span className={`${classPrefix}__badge-ok`}>✓</span>
                ) : (
                  <span
                    className={`${classPrefix}__nav-dot${navSel.area === 'around' ? ` ${classPrefix}__nav-dot--active` : ''}`}
                  />
                )}
                <span className={`${classPrefix}__nav-label`}>
                  Around the Building
                </span>
                {(aroundApiData?.findingCount ?? 0) > 0 && (
                  <span className={`${classPrefix}__nav-badge`}>
                    {aroundApiData.findingCount}
                  </span>
                )}
              </div>

              {/* Inside the Building group tab 二二二二 */}
              <div
                className={`${classPrefix}__nav-group-header${navSel.area === 'inside' ? ` ${classPrefix}__nav-group-header--active` : ''}`}
                onClick={() => handleNavSel('inside', INSIDE_FLOORS[0])}
              >
                {insideApiData?.floorSummaryList?.length > 0 &&
                insideApiData.floorSummaryList.every(
                  (f: any) => f.saveStatus === 1,
                ) ? (
                  <span className={`${classPrefix}__badge-ok`}>✓</span>
                ) : (
                  <span
                    className={`${classPrefix}__nav-dot${navSel.area === 'inside' ? ` ${classPrefix}__nav-dot--active` : ''}`}
                  />
                )}
                <span className={`${classPrefix}__nav-label`}>
                  Inside the Building
                </span>
                {(insideApiData?.findingCount ?? 0) > 0 && (
                  <span className={`${classPrefix}__nav-badge`}>
                    {insideApiData.findingCount}
                  </span>
                )}
              </div>
              {INSIDE_FLOORS.map((floor) => {
                const floorData = getInsideFloorData(floor)
                const isActive =
                  navSel.area === 'inside' &&
                  navSel.floor?.value === floor.value
                return (
                  <div
                    key={floor.value}
                    className={`${classPrefix}__nav-child${isActive ? ` ${classPrefix}__nav-child--active` : ''}`}
                    onClick={() => handleNavSel('inside', floor)}
                  >
                    {floorData?.saveStatus === 1 ? (
                      <span className={`${classPrefix}__badge-ok`}>✓</span>
                    ) : (
                      <span
                        className={`${classPrefix}__nav-child-dot${isActive ? ` ${classPrefix}__nav-child-dot--active` : ''}`}
                      />
                    )}
                    <span className={`${classPrefix}__nav-label`}>
                      Floor {floor.label}
                    </span>
                    {(floorData?.findingCount ?? 0) > 0 && (
                      <span className={`${classPrefix}__nav-badge`}>
                        {floorData.findingCount}
                      </span>
                    )}
                  </div>
                )
              })}

              {/* Parking group tab 三三三三 */}
              <div
                className={`${classPrefix}__nav-group-header${navSel.area === 'parking' ? ` ${classPrefix}__nav-group-header--active` : ''}`}
                onClick={() => handleNavSel('parking', PARKING_SUBS[0])}
              >
                {parkingApiData?.floorSummaryList?.length > 0 &&
                parkingApiData.floorSummaryList.every(
                  (f: any) => f.saveStatus === 1,
                ) ? (
                  <span className={`${classPrefix}__badge-ok`}>✓</span>
                ) : (
                  <span
                    className={`${classPrefix}__nav-dot${navSel.area === 'parking' ? ` ${classPrefix}__nav-dot--active` : ''}`}
                  />
                )}
                <span className={`${classPrefix}__nav-label`}>Parking</span>
                {(parkingApiData?.findingCount ?? 0) > 0 && (
                  <span className={`${classPrefix}__nav-badge`}>
                    {parkingApiData.findingCount}
                  </span>
                )}
              </div>
              {PARKING_SUBS.map((sub) => {
                const subData = getParkingSubData(sub)
                const isActive =
                  navSel.area === 'parking' && navSel.sub?.value === sub.value
                return (
                  <div
                    key={sub.value}
                    className={`${classPrefix}__nav-child${isActive ? ` ${classPrefix}__nav-child--active` : ''}`}
                    onClick={() => handleNavSel('parking', sub)}
                  >
                    {subData?.saveStatus === 1 ? (
                      <span className={`${classPrefix}__badge-ok`}>✓</span>
                    ) : (
                      <span
                        className={`${classPrefix}__nav-child-dot${isActive ? ` ${classPrefix}__nav-child-dot--active` : ''}`}
                      />
                    )}
                    <span className={`${classPrefix}__nav-label`}>
                      {sub.label}
                    </span>
                    {(subData?.findingCount ?? 0) > 0 && (
                      <span className={`${classPrefix}__nav-badge`}>
                        {subData.findingCount}
                      </span>
                    )}
                  </div>
                )
              })}
            </div>

            {/* Content area */}
            <div className={`${classPrefix}__content-area`}>
              <Form form={form} layout='vertical'>
                <div className={`${classPrefix}__content-header`}>
                  <div>
                    <div className={`${classPrefix}__content-title`}>
                      {contentTitle}
                    </div>
                    <div className={`${classPrefix}__content-subtitle`}>
                      Please click "Checked" after each floor/area is finished.
                    </div>
                  </div>
                  <Button
                    type='primary'
                    className={`${classPrefix}__check-save-btn`}
                    icon={<IconSave />}
                    loading={patrolFormSaveLoading}
                    onClick={handleCheckSave}
                  >
                    Check &amp; Save
                  </Button>
                </div>

                <div className={`${classPrefix}__sections`}>
                  {patrolDetailLoading && !dynamicSections.length ? (
                    <div className={`${classPrefix}__loading`}>
                      <Spin />
                    </div>
                  ) : (
                    dynamicSections?.map((section) => (
                      <SectionCard
                        key={section.id}
                        form={form}
                        section={section}
                        orgData={orgData}
                      />
                    ))
                  )}
                </div>
              </Form>
            </div>
          </div>

          {/* Footer */}
          <div className={`${classPrefix}__footer`}>
            <Button icon={<IconClose />} onClick={() => navigate(-1)}>
              Cancel
            </Button>
            <Tooltip
              content={
                !isAllSaved
                  ? 'Please complete and save all sections before submitting'
                  : undefined
              }
              disabled={isAllSaved}
            >
              <Button
                type='primary'
                icon={<IconUpload />}
                onClick={handleSubmit}
                disabled={!isAllSaved}
              >
                Submit for Approval
              </Button>
            </Tooltip>
          </div>
        </div>
      </div>

      {/* Submit confirmation modal */}
      <Modal
        visible={submitModalVisible}
        onCancel={() => setSubmitModalVisible(false)}
        footer={null}
        title={null}
        closable
        maskClosable={false}
        style={{ width: 400 }}
      >
        <div className={`${classPrefix}__confirm-modal`}>
          <div className={`${classPrefix}__confirm-modal-header`}>
            <IconInfoCircleFill
              className={`${classPrefix}__confirm-modal-icon`}
            />
            <div>
              <div className={`${classPrefix}__confirm-modal-title`}>
                Submit Confirmation
              </div>
              <div className={`${classPrefix}__confirm-modal-desc`}>
                Are you sure to submit?
              </div>
            </div>
          </div>
          <div className={`${classPrefix}__confirm-modal-footer`}>
            <Button onClick={() => setSubmitModalVisible(false)}>Cancel</Button>
            <Button type='primary' onClick={handleConfirmSubmit}>
              Confirm
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  )
}

