          body[dir='rtl'] & {
            padding-right: 3px;
          }
        }
      }

      .incident-dynamic-table {
        width: 100%;
        border-collapse: separate;
        border-spacing: 0;
        border: 1px solid #e5e6eb;
        border-radius: 8px;
        overflow: hidden;
        background: #fff;
        // border: 1px solid red;

        thead tr {
          background: #f7f8fa;
        }

        th {
          padding: 10px 12px;
          text-align: left;
          font-weight: 500;
          font-size: 13px;
          color: #1d2129;
          border-bottom: 1px solid #e5e6eb;
          .ant-form-item-required {
            color: rgb(var(--danger-6));
            margin-right: 4px;
            font-size: 20px;
            align-items: center;
          }
        }

        td {
          padding: 8px 12px;
          vertical-align: middle;
          border-bottom: 1px solid #e5e6eb;
          background: #fff;

          .formblink-enter-done {
            display: none;
          }
        }

        /* 动态表格内字段垂直居中 */
        .incident-dynamic-table__cell-item {
          margin-bottom: 0;
          display: flex;
          align-items: center;
          min-height: 36px;
        }

        .incident-dynamic-table__cell-item [class*='form-item-control'] {
          width: 100%;
          display: flex;
          align-items: center;
        }

        .arco-form-item {
          margin-bottom: 0;
        }

        .arco-form-item-message {
          display: none;
        }
        .incident-dynamic-table__cell-item .arco-form-item-message,
        .incident-dynamic-table__cell-item .arco-form-item-help,
        .incident-dynamic-table__cell-item .arco-form-item-extra,
        .incident-dynamic-table__cell-item [class*='form-item-message'],
        .incident-dynamic-table__cell-item [class*='form-item-help'] {
          display: none !important;
          min-height: 0 !important;
          margin: 0 !important;
        }

        tbody tr:last-child td {
          border-bottom: none;
        }

        .arco-input,
        .arco-textarea,
        .arco-select-view {
          border: 1px solid transparent;
          background: transparent;
          border-radius: 4px;
        }

        .arco-select-view {
          width: 100%;
        }

        .arco-input:focus,
        .arco-textarea:focus,
        .arco-select-view:focus-within {
          border-color: var(--color-primary-light-3);
          background: #fff;
        }

        /* Form 校验失败后，错误态无需 hover/focus 也保持红框 */
        .arco-form-item-status-error .arco-input,
        .arco-form-item-status-error .arco-textarea,
        .arco-form-item-status-error .arco-select-view,
        .arco-input-error,
        .arco-textarea-error,
        .arco-select-view-error {
          border-color: rgb(var(--red-6)) !important;
          background: #fff2f0;
        }

        &__readonly .arco-input {
          color: #86909c;
          cursor: default;
        }

        &__col-action {
          width: 48px;
          text-align: center;
          vertical-align: middle;
        }

        &__btn-delete {
          color: rgb(var(--red-6)) !important;
        }

        &__add {
          margin-top: 12px;
          padding-left: 0 !important;
          color: #30647f !important;
          font-weight: 500;

          .arco-icon {
            color: #30647f;
          }
        }
      }
    }
    // ── Incident ID bar ──
    .incident-id-bar {
      display: flex;
      align-items: center;
      gap: 16px;
      padding: 12px 0 8px;
      font-size: 14px;

      &__label {
        color: #86909c;
      }

      &__value {
        font-weight: 600;
        color: #1d2129;
      }
    }

    // ── Section headers ──
    .section-header {
      text-transform: uppercase;
      color: #1d2129;
      padding: 20px 0 12px;
      margin-bottom: 20px;
      letter-spacing: 0.02em;
      font-weight: 500px;
      font-size: 24px;
      line-height: 100%;
    }

    // ── Floor selector ──
    .floor-selector {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;

      .floor-btn {
        min-width: 40px;
        height: 40px;
        padding: 0 10px;
        border: 1px solid #e5e6eb;
        border-radius: 6px;
        background: #fff;
        cursor: pointer;
        font-size: 14px;
        color: #1d2129;
        transition:
          border-color 0.2s,
          color 0.2s,
          background 0.2s;

        &:hover {
          border-color: #30647f;
          color: #30647f;
        }

        &.selected {
          border-color: #30647f;
          color: #30647f;
          background: #e8fbff;
        }

        &:disabled {
          cursor: not-allowed;
          background: #f7f8fa;
          color: #c9cdd4;
          border-color: #e5e6eb;

          &:hover {
            border-color: #e5e6eb;
            color: #c9cdd4;
          }

          &.selected {
            color: #94bfff;
            border-color: #bedaff;
            background: #f2f7ff;
          }
        }
      }
    }

    // ── Party blocks (External Party Involved) ──
    .party-block {
      border: 1px solid #e5e6eb;
      border-radius: 8px;
      margin-bottom: 10px;
      overflow: hidden;
    }

    .party-block-header {
      display: flex;
      align-items: center;
      gap: 10px;
      padding: 10px 16px;
      background: #f7f8fa;
      cursor: pointer;
      user-select: none;

      &--checked {
        background: #e8f3ff;
      }

      &__icon {
        font-size: 16px;
      }

      &__label {
        font-weight: 600;
        font-size: 14px;
        text-transform: uppercase;
        color: #1d2129;
      }
    }

    .party-block-content {
      padding: 16px;
      background: #fff;
    }

    // ── Impact blocks ──
    .impact-block {
      border: 1px solid #e5e6eb;
      border-radius: 8px;
      margin-bottom: 10px;
      overflow: hidden;
    }

    .impact-block-header {
      display: flex;
      align-items: center;
      gap: 10px;
      padding: 10px 16px;
      background: #f7f8fa;
      cursor: pointer;
      user-select: none;
      font-weight: 600;
      font-size: 14px;
      text-transform: uppercase;
      color: #1d2129;

      &--checked {
        background: #e8f3ff;
      }

      &__icon {
        font-size: 16px;
      }
    }

    .impact-block-content {
      padding: 16px;
      background: #fff;
    }

    // ── Issue items ──
    .issue-item {
      border: 1px solid #e5e6eb;
      border-radius: 8px;
      padding: 16px;
      margin-bottom: 16px;
      background: #fff;
    }

    .issue-item-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 16px;

      &__title {
        font-weight: 700;
        font-size: 14px;
        text-transform: uppercase;
        color: #1d2129;
      }

      &__delete {
        color: rgb(var(--red-6)) !important;
      }
    }

    .issues-add-btn {
      margin-top: 4px;
      margin-bottom: 16px;
    }

    .addOrEdit-right {
      display: flex;
      flex: 0 0 388px;

      // border: 1px solid red;

      .approval-progress-card {
        width: 100%;
        height: 100%;
        display: flex;
        flex-direction: column;
      }

      .approval-progress-card__content {
        flex: 1;
      }
    }
  }
  .addOrEdit-footer {
    display: flex;
    justify-content: end;
    gap: 8px;
    border-top: 1px solid rgb(226, 226, 226);
    padding: 14px 10px 0px 10px;
    border: 1px solid red;
    &__btn {
      width: 104px;
    }
  }
}

