        display: block;
      }
      &--line {
        margin: 0 16px;
        width: 1px;
        height: 16px;
        background-color: #fff;

        .is-orgu-theme & {
          background-color: #86909c;
        }
      }
      &--text {
        color: #fff;

        .is-orgu-theme & {
          color: #1d2129;
        }

        font-size: 22px;
        font-weight: @font-weight-medium;
        text-transform: uppercase;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
      }
    }

    &__btn {
      padding: 12px 20px;
      display: flex;
      flex-direction: row;
      align-items: center;
      justify-content: center;

      &--lng {
        font-size: 12px;
        // color: @gray-4e5969;
        font-weight: @font-weight-medium;
        display: flex;
        justify-content: center;
        align-items: center;

        html[lang='ar'] & {
          font-size: 14px;
        }

        &.arco-btn-shape-circle {
          background-color: rgba(255, 255, 255, 0.6);

          .is-orga-theme &,
          .is-orgu-theme & {
            background-color: @color-special;

            &:hover {
              background-color: @color-hover;
            }
          }

          .is-orgu-theme & {
            svg path {
              fill: @color-press;
            }
          }
        }

        &.btn-locale {
          svg {
            font-size: 30px;
          }
        }
      }

      img {
        width: 100%;
        height: auto;
        object-fit: contain;
      }
    }

    &__user-info {
      padding: 10px 12px 12px;

      background: #ffffff;

      // border: 1px solid @gray-e5e6eb;
      /* shadow/一级下拉菜单 */
      box-shadow: 0px 4px 10px rgba(0, 0, 0, 0.1);
      border-radius: 4px;

      &__item {
        padding-top: 8px;
        &__name {
          font-style: normal;
          font-weight: @font-weight-medium;
          font-size: 16px;
          line-height: 20px;
          text-transform: capitalize;
          // color: @black-1d2129;
          text-wrap: wrap;
          max-width: 190px;

          html[lang='ar'] & {
            font-weight: @font-weight-medium;
            font-size: 18px;
          }
        }

        &__tags {
          max-width: 190px;
          display: flex;
          flex-direction: row;
          flex-wrap: wrap;
          overflow: hidden;

          .arco-space-item {
            max-width: 100%;
          }
        }

        &__tag {
          display: block;
          padding: 0 8px;
          margin-top: 8px;

          font-style: normal;
          font-weight: @font-weight-medium;
          font-size: 12px;
          line-height: 20px;
          color: #165dff;

          background: #e8f3ff;
          border-radius: 21px;

          html[lang='ar'] & {
            font-weight: @font-weight-medium;
            font-size: 14px;
          }

          &--last {
            background-color: #e8ffea;
            color: #00b42a;
          }
        }
      }
    }
  }
}
.confirm-logout-modal {
  .arco-modal-content {
    padding-bottom: 0;
  }
  .log-out-confirm-box {
    display: flex;
    flex-wrap: nowrap;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    .warning-icon {
      width: 34px;
      height: 34px;
    }
    .log-out-title {
      color: #1d2129;
      font-size: 24px;
      font-weight: 700;
      margin-top: 12px;
    }
    .log-out-content {
      color: #808080;
      text-align: center;
      font-size: 14px;
      font-weight: 400;
      padding: 16px 0;
    }
  }
  .arco-modal-footer {
    display: flex;
    justify-content: center;
    .arco-btn-status-danger {
      background: linear-gradient(180deg, #ee5c62 0%, #e9494f 100%);
    }
  }
}

