file.content:
.page-wrapper {
  //   min-width: 1170px;
  height: 100%;
  box-sizing: border-box;
  overflow: hidden;
  border-radius: 4px;
  &__breadcrumb {
    line-height: 48px;
  }
  &.table-page {
    display: flex;
    min-width: 1010px;
  }

  &__layout {
    background-color: @color-white;
    box-sizing: border-box;
    margin-top: 20px;
    height: 100%;
    box-sizing: border-box;
    overflow-y: auto;
    border-radius: 12px;
    box-shadow: 0px 4px 10px rgba(0, 0, 0, 0.05);
    padding-bottom: 20px;
    .table-page & {
      overflow-y: hidden;
    }
    &.reset-margin-top {
      margin-top: 0;
    }

    &--bread {
      margin-top: 0;
      padding-bottom: 0;
    }
  }

  &__header {
    height: 48px;
    line-height: 48px;
    padding: 0 20px;
    box-sizing: border-box;
    border-bottom: 1px solid @gray-e5e6eb;
    font-size: 16px;
    font-weight: @font-weight-medium;
    color: @black-1d2129;
    font-style: normal;
    &__content {
      display: flex;
      justify-content: space-between;
    }

    html[lang='ar'] & {
      font-size: 22px;
    }
  }

  &__main {
    padding: 16px;
    position: relative;
    box-sizing: border-box;
    &--no-padding {
      padding: 0;
    }
    &--reset-page-wrapper-padding {
      padding: 0;
    }
  }
}

