          <div>
            <AddOrEdit
              current={current}
              userList={userList}
              setShowStatus={setShowStatus}
            />
          </div>
        )}
        {(current == IncidentReportStep.StepThree ||
          current == IncidentReportStep.StepFour) && (
          <div>
            <IncidentReportDetail
              current={current}
              userList={userList}
              setShowStatus={setShowStatus}
            />
          </div>
        )}
      </div>
    </PageWrapper>
  </div>
)

