import React, { memo } from 'react'
import { Layout, Breadcrumb } from '@arco-design/web-react'
import classNames from 'classnames'
import { NavLink } from 'react-router-dom'

import './index.less'
import type { RouteProps } from '@arco-design/web-react/es/Breadcrumb/interface'
// import usePageWrapperMinWidth from '@/hooks/usePageWrapperMinWidth'

const Header = Layout.Header
const Content = Layout.Content
const BreadcrumbItem = Breadcrumb.Item

interface PageWrapperProps {
  pageClassName?: string
  showHeader?: boolean
  hseHeader?: boolean
  headerTitle?: string | React.ReactNode
  headerClassName?: string
  contentClassName?: string
  children?: React.ReactNode
  showBreadcrumb?: boolean
  routes?: RouteProps[]
  tablePageClassName?: string
  hasMoreListFilterRows?: boolean
  resetMarginTop?: boolean
  resetPageWrapperPadding?: boolean
  showCustomHeader?: boolean
  customHeaderDom?: string | React.ReactNode
}

const classPrefix = 'page-wrapper'

const PageWrapper: React.FC<PageWrapperProps> = ({
  pageClassName,
  headerTitle,
  headerClassName,
  contentClassName,
  showHeader = true,
  hseHeader = true,
  showBreadcrumb = false,
  routes,
  children,
  tablePageClassName,
  hasMoreListFilterRows = false,
  resetMarginTop = false,
  resetPageWrapperPadding = false,
  showCustomHeader = false,
  customHeaderDom,
}) => {
  // const pageWrapperMinWidth = usePageWrapperMinWidth()

  return (
    <div
      className={classNames({
        [`${classPrefix}`]: true,
        [`${pageClassName}`]: pageClassName,
        [`${tablePageClassName}`]: tablePageClassName,
      })}
      style={
        {
          // minWidth: pageWrapperMinWidth + 'px',
        }
      }
    >
      {showBreadcrumb && (
        <Breadcrumb
          separator='/'
          className={classNames({
            [`${classPrefix}__breadcrumb`]: true,
          })}
        >
          {routes?.map((route, i) => (
            <BreadcrumbItem key={route.path}>
              {i === routes.length - 1 ? (
                <span>{route.breadcrumbName}</span>
              ) : (
                <NavLink to={route.path}>{route.breadcrumbName}</NavLink>
              )}
            </BreadcrumbItem>
          ))}
        </Breadcrumb>
      )}

      <Layout
        className={classNames({
          [`${classPrefix}__layout`]: true,
          [`${classPrefix}__layout--bread`]: showBreadcrumb,
          [`reset-margin-top`]: resetMarginTop,
        })}
      >
        {showHeader && hseHeader && (
          <Header
            className={classNames({
              [`${classPrefix}__header`]: true,
              [`${headerClassName}`]: headerClassName,
            })}
          >
            {showCustomHeader ? customHeaderDom : headerTitle}
          </Header>
        )}
        <Content
          className={classNames({
            [`${classPrefix}__main`]: true,
            [`${classPrefix}__main--no-padding`]: !showHeader,
            [`${contentClassName}`]: contentClassName,
            [`${classPrefix}__main--reset-page-wrapper-padding`]:
              resetPageWrapperPadding,
          })}
          style={{ overflowY: hasMoreListFilterRows ? 'auto' : 'initial' }}
        >
          {children}
        </Content>
      </Layout>
    </div>
  )
}

export default memo(PageWrapper)

