import { useEffect, useState } from 'react'
import { Badge } from '@arco-design/web-react'
import BreadcrumbNav from '@common/Layout/components/BreadcrumbNav'
import PageWrapper from '@common/components/PageWrapper'
import { LanguageEnum } from '@common/constants/language'
import { getLanguage } from '@common/utils/localStorage'
import { useTranslation } from 'react-i18next'
import { useParams } from 'react-router-dom'
import _ from 'lodash'
import './index.less'
import AddOrEdit from '../components/AddOrEdit'
import IncidentReportDetail from '../components/IncidentReportDetail'
import { IncidentReportStep } from '@/constants/incidentReport'
import { useRequest } from 'ahooks'
import { getUserListAll } from '@/service'
const IncidentReportAddOrEdit = () => {
  const { t } = useTranslation([
    'common',
    'project',
    'activities',
    'incidentReport',
  ])
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const { step } = useParams()
  const current = +step
  const [userList, setUserList] = useState<any>()
  const [showStatus, setShowStatus] = useState<any>()
  const breadcrumbList = [
    {
      path: '/incident-report/incident-report-management/list',
      breadcrumbName: t('incidentReport:title'),
    },
    {
      path: '/incident-report/incident-report-management/addOrEdit',
      breadcrumbName: t('incidentReport:columns.incidentDetails'),
    },
  ]

  const colorFunction = (value) => {
    if (value == 0) {
      return { color: '#4080FF', name: t('incidentReport:status.open') }
    } else if (value == 1) {
      return { color: '#FF7D00', name: t('incidentReport:status.underReview') }
    } else if (value == 2) {
      return { color: '#F5626C', name: t('incidentReport:status.rejected') }
    } else {
      return { color: '#45AD5E', name: t('incidentReport:status.approved') }
    }
  }

  const headerDom = () => {
    return (
      <div className='step-header'>
        <div className='header-title'>
          {t('incidentReport:columns.incidentDetails')}
        </div>
        <div className={`header-label color-box-${showStatus}`}>
          <Badge color={colorFunction(showStatus).color} />
          <span>{colorFunction(showStatus).name}</span>
        </div>
      </div>
    )
  }

  const { run: runGetUserListAll, loading: getUserListAllLoading } = useRequest(
    getUserListAll,
    {
      manual: true,
      onSuccess: (res: any) => {
        const data = res?.map((item: any) => {
          return {
            value: item.userId,
            label: isLanguageAR ? item.fullNameAr : item.fullName,
          }
        })
        setUserList(data)
      },
    },
  )

  useEffect(() => {
    runGetUserListAll({})
  }, [])

  return (
    <div className='incidentReport-step'>
      <BreadcrumbNav routes={breadcrumbList} />
      <PageWrapper
        resetMarginTop={true}
        headerTitle={headerDom()}
        contentClassName='incidentReport-step-content'
      >
        <div>
          {current == IncidentReportStep.StepTwo && (
            <div>
              <AddOrEdit
                current={current}
                userList={userList}
                setShowStatus={setShowStatus}
              />
            </div>
          )}
          {(current == IncidentReportStep.StepThree ||
            current == IncidentReportStep.StepFour) && (
            <div>
              <IncidentReportDetail
                current={current}
                userList={userList}
                setShowStatus={setShowStatus}
              />
            </div>
          )}
        </div>
      </PageWrapper>
    </div>
  )
}
export default IncidentReportAddOrEdit

import { Breadcrumb } from "@arco-design/web-react"
import { NavLink } from 'react-router-dom'
import './BreadcrumbNav.less'

const BreadcrumbItem = Breadcrumb.Item

const BreadcrumbNav = ({ routes = [] }) => {
  return (
    <Breadcrumb
      separator='/'
      style={{ lineHeight: '48px' }}
    >
      {routes?.map((route, i) => (
        <BreadcrumbItem key={route.path}>
          {i === routes.length - 1 ? (
            <span className="breadcrumbNav-end">{route.breadcrumbName}</span>
          ) : (
            <NavLink to={route.path}>{route.breadcrumbName}</NavLink>
          )}
        </BreadcrumbItem>
      ))}
    </Breadcrumb>
  )
}

export default BreadcrumbNav

