.incidentReportDetail {
  background: #fff;
  margin-top: -20px;

  .incidentReportDetail-top {
    display: flex;

    .incidentReportDetail-top-left {
      flex: 1;
      min-width: 0;
      padding: 0 26px 26px;

      // ── Incident meta bar ──
      .incident-meta-bar {
        display: flex;
        align-items: center;
        flex-wrap: wrap;
        gap: 8px;
        padding: 16px 0 8px;
        font-size: 14px;
        border-bottom: 1px solid #f2f3f5;
        margin-bottom: 4px;

        .meta-label {
          color: #4e5969;
          font-weight: 400;
          font-size: 14px;
          line-height: 22px;
        }

        .meta-value {
          font-weight: 400;
          font-size: 14px;
          line-height: 22px;
          color: #1d2129;
        }

        .meta-sep {
          color: #c9cdd4;
        }

        .meta-link {
          color: #30647f;
          cursor: pointer;
          text-decoration: none;

          &:hover {
            text-decoration: underline;
          }
        }
      }

      // ── Section headers ──
      .section-header {
        font-size: 16px;
        font-weight: 700;
        text-transform: uppercase;
        color: #1d2129;
        padding: 20px 0 12px;
        border-bottom: 1px solid #e5e6eb;
        margin-bottom: 16px;
        letter-spacing: 0.02em;
      }

      // ── Info rows ──
      .info {
        padding-bottom: 16px;

        .label {
          font-weight: 400;
          font-size: 13px;
          line-height: 20px;
          color: #86909c;
          margin-bottom: 4px;
        }

        .value {
          font-weight: 400;
          font-size: 14px;
          line-height: 22px;
          color: #1d2129;
          word-break: break-word;
        }

        .attachment {
          display: flex;
          flex-wrap: wrap;
          gap: 10px;
          margin-top: 8px;

          .item {
            width: 80px;
            height: 80px;
            border-radius: 4px;
            overflow: hidden;
            border: 1px solid #e5e6eb;
          }
        }
      }

      // ── External Party Involved Yes/No display ──
      .incidentDom-readonly {
        display: flex;
        width: 240px;
        height: 36px;
        align-items: center;
        background-color: #f7f8fa;
        border-radius: 6px;
        overflow: hidden;

        &__btn {
          flex: 1;
          height: 28px;
          margin: 0 4px;
          display: flex;
          justify-content: center;
          align-items: center;
          font-size: 14px;
          color: #86909c;
          border-radius: 4px;

          &--active {
            background-color: #30647f;
            color: #fff;
          }
        }
      }

      // ── Party blocks ──
      .party-block {
        border: 1px solid #e5e6eb;
        border-radius: 8px;
        margin-bottom: 10px;
        overflow: hidden;
      }

      .party-block-header {
        display: flex;
        align-items: center;
        gap: 10px;
        padding: 10px 16px;
        background: #f0f5f8;

        &__icon {
          font-size: 15px;
        }

        &__label {
          font-weight: 600;
          font-size: 13px;
          text-transform: uppercase;
          color: #1d2129;
        }
      }

      .party-block-content {
        padding: 12px 16px 4px;
        background: #fff;

        // Horizontal two-column layout inside party blocks
        .info {
          display: flex;
          flex-direction: row;
          align-items: flex-start;
          padding-bottom: 12px;

          .label {
            flex: 0 0 150px;
            min-width: 150px;
            margin-bottom: 0;
            padding-top: 1px;
          }

          .value {
            flex: 1;
            min-width: 0;
          }

          .attachment {
            flex: 1;
            min-width: 0;
            margin-top: 0;
          }
        }
      }

      // ── Impact blocks ──
      .impact-block {
        border: 1px solid #e5e6eb;
        border-radius: 8px;
        margin-bottom: 10px;
        overflow: hidden;
      }

      .impact-block-header {
        display: flex;
        align-items: center;
        gap: 10px;
        padding: 10px 16px;
        background: #f0f5f8;
        font-weight: 600;
        font-size: 13px;
        text-transform: uppercase;
        color: #1d2129;

        &__icon {
          font-size: 15px;
        }
      }

      .impact-block-content {
        padding: 12px 16px;
        background: #fff;
      }

      // ── Issue items ──
      .issue-item {
        border: 1px solid #e5e6eb;
        border-radius: 8px;
        padding: 16px;
        margin-bottom: 16px;
        background: #fff;
      }

      .issue-item-header {
        margin-bottom: 12px;

        &__title {
          font-weight: 700;
          font-size: 14px;
          text-transform: uppercase;
          color: #1d2129;
        }
      }
    }

    .incidentReportDetail-top-right {
      display: flex;
      flex: 0 0 388px;

      body[dir='ltr'] & {
        border-left: 1px solid #e5e6eb;
      }

      body[dir='rtl'] & {
        border-right: 1px solid #e5e6eb;
      }

      .approval-progress-card {
        width: 100%;
        height: 100%;
        display: flex;
        flex-direction: column;
      }

      .approval-progress-card__content {
        flex: 1;
      }
    }
  }

  .incidentReportDetail-bottom {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    border-top: 1px solid rgb(226, 226, 226);
    padding: 14px 16px;
    justify-content: end;
    .footer__btn {
      min-width: 96px;
    }

    .footer-comment {
      flex: 1;
      max-width: 320px;

      &__label {
        font-size: 13px;
        color: #86909c;
        margin-bottom: 4px;
      }

      &__input {
        resize: none;
      }
    }
  }

  .exportPDF-box {
    position: fixed;
    top: 0;
    left: -100000px;
    z-index: -1;
    pointer-events: none;
  }
}

